import {IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _untwisting_iron_strength = {title: "Untwisting Iron Strength", jsx: <><h2 id="feat-untwisting_iron_strength-untwisting-iron-strength-combat">Untwisting Iron Strength (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 107</Link>, <Link to="/source/inner_sea_combat">Inner Sea Combat pg. 13</Link></p>
<p>You are a master at breaking even the toughest of objects.<br/><strong>Prerequisites:</strong> Str 15; Wis 13; <Link to="/feat/perfect_style">Perfect Style</Link>; base attack bonus +9 or monk level 9th.<br/><strong>Benefit:</strong> When using Perfect Style, your attacks ignore an amount of hardness equal to your character level. Additionally, you gain a +4 bonus on Strength checks to break objects. If you spend 1 ki point as a swift action, you also gain the benefits of <Link to="/feat/improved_sunder">Improved Sunder</Link> for 1 round.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-untwisting_iron_strength--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-untwisting_iron_strength-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 25</Link><br/>You can spend 2 stamina points instead of 1 ki point when using Untwisting Iron Strength.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _unusual_heritage_changeling = {title: "Unusual Heritage (Changeling)", jsx: <><h2 id="feat-unusual_heritage_changeling-unusual-heritage-changeling-teamwork">Unusual Heritage (Changeling) (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion pg. 17</Link></p>
<p>Your heritage is strange or difficult to trace, and people fear your otherworldly powers.<br/><strong>Prerequisites:</strong> <Link to="/race/changeling">Changeling</Link>.<br/><strong>Benefit:</strong> Your mother was part of a powerful hag coven, and it shows when you are near your kin. As long as you are within 30 feet of at least two other changelings, you gain a +2 bonus on <Link to="/rule/concentration">concentration</Link> checks and dispel checks. If at least two of these changelings also have this feat, these bonuses increase to +4.<br/><strong>Special:</strong> This version of Unusual Heritage is a teamwork feat.</p>
</>};
const _unusual_heritage_dhampir = {title: "Unusual Heritage (Dhampir)", jsx: <><h2 id="feat-unusual_heritage_dhampir-unusual-heritage-dhampir">Unusual Heritage (Dhampir)</h2>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion pg. 16</Link></p>
<p>Your heritage is strange or difficult to trace, and people fear your otherworldly powers.<br/><strong>Prerequisites:</strong> <Link to="/race/dhampir">Dhampir</Link>.<br/><strong>Benefit:</strong> Your undead progenitor left you with more than a hint of vampiric nature. You gain a natural bite attack that deals 1d4 points of damage. Once per day upon making a successful bite attack, you can choose to deal an additional 1d4 points of <Link to="/rule/bleed">bleed</Link> damage to the creature struck.<br/><strong>Special:</strong> You can only select this feat at 1st level.</p>
</>};
const _unusual_heritage_fetchling = {title: "Unusual Heritage (Fetchling)", jsx: <><h2 id="feat-unusual_heritage_fetchling-unusual-heritage-fetchling">Unusual Heritage (Fetchling)</h2>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion pg. 17</Link></p>
<p>Your heritage is strange or difficult to trace, and people fear your otherworldly powers.<br/><strong>Prerequisites:</strong> <Link to="/race/fetchling">Fetchling</Link>.<br/><strong>Benefit:</strong> You have the mysterious ability to see into the <Link to="/rule/shadow_plane">Shadow Plane</Link>, but only in your dreams. Once per day while sleeping, you can create a magical sensor, as <Link to="/spell/arcane_eye">arcane eye</Link> except this sensor can view only your current location as it exists on the Shadow Plane. This effect lasts for 1 minute per character level, and can be used during any point while you sleep.</p>
</>};
const _unusual_heritage_gillman = {title: "Unusual Heritage (Gillman)", jsx: <><h2 id="feat-unusual_heritage_gillman-unusual-heritage-gillman">Unusual Heritage (Gillman)</h2>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion pg. 16</Link></p>
<p>Your heritage is strange or difficult to trace, and people fear your otherworldly powers.<br/><strong>Prerequisites:</strong> <Link to="/race/gillman">Gillman</Link>.<br/><strong>Benefit:</strong> As a so-called "Low Azlanti," you have abilities supposedly tied to mysterious ancestors who still watch over you and your ilk. Your divination spells and spell-like abilities manifest at 1 caster level higher. In addition, once per day while fully immersed in water, you can cast <Link to="/spell/augury">augury</Link> as a spell-like ability.</p>
</>};
const _unyielding_ferocity = {title: "Unyielding Ferocity", jsx: <><h2 id="feat-unyielding_ferocity-unyielding-ferocity-combat">Unyielding Ferocity (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 95</Link></p>
<p>When near the brink of death, you fight ferociously until the bitter end.<br/><strong>Prerequisites:</strong> Con 19, ferocity.<br/><strong>Benefit:</strong> When you are reduced to 0 or fewer hit points, if you remain conscious from your <Link to="/umr/ferocity">ferocity</Link> monster ability, you can make a full attack on your next turn (or your current turn if you are reduced to 0 hit points on your own turn). If you do, you push your body to the point that your mind becomes more primitive, and you can no longer use any Charisma-, Dexterity-, or Intelligence-based skills except Acrobatics, Fly, Intimidate, or Ride, or any ability that requires patience or concentration (such as spellcasting) until your hit points are raised above 0.<br/><strong>Normal:</strong> When using the ferocity ability, you are <Link to="/misc/staggered">staggered</Link> while you have fewer than 0 hit points and thus can't make a full attack.</p>
</>};
const _upsetting_shield_style = {title: "Upsetting Shield Style", jsx: <><h2 id="feat-upsetting_shield_style-upsetting-shield-style-combat-style">Upsetting Shield Style (Combat, Style)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 12</Link></p>
<p>You can strike at weapons to upset enemy attacks.<br/><strong>Prerequisites:</strong> Dex 13, proficiency with bucklers.<br/><strong>Benefit:</strong> You can <Link to="/misc/shield_bash">shield bash</Link> with a buckler as if it were a <Link to="/eq-armor/light_shield">light shield</Link>, and you can use the buckler in conjunction with any feats or abilities that normally apply to light shields. While using this style, whenever you successfully deal damage to an opponent with a shield bash using your buckler, that opponent takes a -2 penalty on all attack rolls made against you until the start of your next turn.</p>
</>};
const _upsetting_strike = {title: "Upsetting Strike", jsx: <><h2 id="feat-upsetting_strike-upsetting-strike-combat">Upsetting Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 13</Link></p>
<p>You can turn the tables on disoriented opponents.<br/><strong>Prerequisites:</strong> Dex 15, <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, <Link to="/feat/improved_shield_bash">Improved Shield Bash</Link>, <Link to="/feat/upsetting_shield_style">Upsetting Shield Style</Link>, proficiency with bucklers.<br/><strong>Benefit:</strong> While you are using Upsetting Shield Style, if a foe is taking a penalty on attack rolls against you as a result of Upsetting Shield Style, and that foe makes a melee attack roll against you that misses your AC by 5 or more, that foe provokes an attack of opportunity from you. You can only make one attack of opportunity against an opponent in this manner each round.</p>
</>};
const _upsetting_vengeance = {title: "Upsetting Vengeance", jsx: <><h2 id="feat-upsetting_vengeance-upsetting-vengeance-combat">Upsetting Vengeance (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 13</Link></p>
<p>You punish those who fail to press their attack.<br/><strong>Prerequisites:</strong> Dex 13, <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, <Link to="/feat/improved_shield_bash">Improved Shield Bash</Link>, <Link to="/feat/upsetting_shield_style">Upsetting Shield Style</Link>, <Link to="/feat/upsetting_strike">Upsetting Strike</Link>, proficiency with bucklers.<br/><strong>Benefit:</strong> While using Upsetting Shield Style, the penalty on attack rolls foes take for being hit by your <Link to="/misc/shield_bash">shield bash</Link> attack applies to their attacks against any target. If an adjacent foe taking this penalty makes an attack roll against any target and misses the target's AC by 5 or more, that foe provokes an attack of opportunity from you. You can only make one attack of opportunity against an opponent as a result of this feat or Upsetting Strike each round.</p>
</>};
const _urban_forager = {title: "Urban Forager", jsx: <><h2 id="feat-urban_forager-urban-forager">Urban Forager</h2>
<p><strong>Sources</strong> <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory pg. 29</Link></p>
<p>You are skilled at keeping yourself and others safe in the alleys, sewers, and underbellies of cities.<br/><strong>Prerequisites:</strong> Knowledge (local) 4 ranks, Survival 4 ranks, Track.<br/><strong>Benefit:</strong> You may use the <Link to="/skill/survival">Survival</Link> skill to forage and track in urban locations using the table below.</p>
<ScrollContainer id="feat-urban_forager--table-0"><table>
<thead>
<tr>
<th>DC</th>
<th>Task</th>
</tr>
</thead>
<tbody><tr>
<td>10</td>
<td>Get along in an urban setting, and easily find enough food and supplies to survive for 24 hours. You can provide food and water for one other person for every 2 points by which your check result exceeds 10.</td>
</tr>
<tr>
<td>15</td>
<td>Gain a +2 bonus on all Constitution checks made to resist starvation or thirst. You may grant the same bonus to one other character for every 1 point by which your Survival check exceeds 15.</td>
</tr>
<tr>
<td>15</td>
<td>Gain a +2 bonus on all Survival checks made to track on firm or hard ground.</td>
</tr>
</tbody></table></ScrollContainer>
</>};
const _urdefhan_bladebreaker = {title: "Urdefhan Bladebreaker", jsx: <><h2 id="feat-urdefhan_bladebreaker-urdefhan-bladebreaker-combat">Urdefhan Bladebreaker (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex pg. 59</Link></p>
<p>You can use your rhoka sword to destroy your foes' blades.<br/><strong>Prerequisites:</strong> Base attack bonus +1, proficiency with the <Link to="/eq-weapon/rhoka_sword">rhoka sword</Link>, <Link to="/monster/urdefhan">urdefhan</Link>.<br/><strong>Benefit:</strong> When wielding a rhoka sword, you can attempt to <Link to="/rule/sunder">sunder</Link> an opponent's sword or other slender-bladed weapon without provoking an attack of opportunity. You gain a +2 circumstance bonus on the combat maneuver check to do so.</p>
</>};
const _ursurping_spell = {title: "Ursurping Spell", jsx: <><h2 id="feat-ursurping_spell-ursurping-spell-metamagic">Ursurping Spell (Metamagic)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_132_the_six_legend_soul">Pathfinder #132: The Six-Legend Soul pg. 73</Link></p>
<p>Like Daronlyr the Overthrower, you lay such brazen claim to power that you force targets of your spells to act as though they were your allies.<br/><strong>Benefit:</strong> A creature that fails its saving throw against a usurping spell counts as your ally rather than your enemy for the purpose of <Link to="/rule/flanking">flanking</Link> other creatures and cannot make attacks of opportunity against you. This effect lasts for the duration of the spell or for 1 round, whichever is longer. A usurping spell uses up a spell slot 1 level higher than the spell's actual level.</p>
</>};
const _usurpers_guard = {title: "Usurper's Guard", jsx: <><h2 id="feat-usurpers_guard-usurpers-guard-teamwork">Usurper's Guard (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_132_the_six_legend_soul">Pathfinder #132: The Six-Legend Soul pg. 73</Link></p>
<p>You work with your allies to create a defensive guard to facilitate spellcasting.<br/><strong>Prerequisites:</strong> Base attack bonus +3 or ability to cast 2nd-level spells.<br/><strong>Benefit:</strong> When an adjacent ally with this feat attempts a <Link to="/rule/concentration">concentration</Link> check to cast a spell or use a spell-like ability defensively, you can attempt a combat maneuver check as an immediate action to guard that ally. Your ally can use either the result of her own concentration check or the result of your combat maneuver check to determine whether she succeeds at casting the spell or using the spell-like ability.</p>
</>};
const _valiant_steed = {title: "Valiant Steed", jsx: <><h2 id="feat-valiant_steed-valiant-steed">Valiant Steed</h2>
<p><strong>Sources</strong> <Link to="/source/animal_archive">Animal Archive pg. 19</Link></p>
<p>Your courage is unnaturally strong.<br/><strong>Prerequisites:</strong> Animal or magical beast.<br/><strong>Benefit:</strong> You gain a +4 morale bonus on saves against fear and emotion effects. If you can serve as a mount, your rider gains a +4 morale bonus on <Link to="/skill/handle_animal">Handle Animal</Link>, <Link to="/skill/ride">Ride</Link>, and <Link to="/ability/wild_empathy">wild empathy</Link> checks to force you within range of a creature with the <Link to="/umr/unnatural_aura">unnatural aura universal monster rule</Link>. In addition, the DC to push you with the Handle Animal skill does not increase if you are wounded or have taken any nonlethal damage or ability score damage.<br/><strong>Normal:</strong> The DC to push an animal increases by 2 if the animal is wounded or has taken any nonlethal damage or ability score damage.</p>
</>};
const _valiant_vault = {title: "Valiant Vault", jsx: <><h2 id="feat-valiant_vault-valiant-vault-mythic">Valiant Vault (Mythic)</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 76</Link></p>
<p>Your mount can make heroic leaps.<br/><strong>Prerequisites:</strong> <Link to="/feat/mounted_combat">Mounted Combat</Link>, <Link to="/feat/ride_by_attack">Ride-By Attack</Link>, Ride 5 ranks.<br/><strong>Benefit:</strong> Your mount is always considered to have a running start when using Acrobatics to jump. You can expend one use of mythic power to grant your mount a +10 bonus on an Acrobatics check, or a +20 bonus if the check is made to jump.</p>
<p>When making a mounted charge, you can guide your mount to leap over a foe between your starting position and the target of your charge. You make a Ride check or your mount makes an Acrobatics check (whichever is lower) during the charge, using the rules for the leap task under the <Link to="/skill/ride">Ride</Link> skill. If the height you clear with that check exceeds the creature's height, you jump over it and continue your charge on the opposite side. This movement provokes attacks of opportunity. Alternatively, you can vault over your target while making a Ride-By Attack, allowing you to move over or through its space and continue moving on the opposite side of it. If your jump exceeds the target's height, you gain a +1 bonus on the attack roll for higher ground, and if any of your allies threatens the target, you treat the target as flanked for purposes of your Ride-By Attack.</p>
</>};
const _vampire_animal_companion = {title: "Vampire Animal Companion", jsx: <><h2 id="feat-vampire_animal_companion-vampire-animal-companion">Vampire Animal Companion</h2>
<p><strong>Sources</strong> <Link to="/source/rival_guide">Rival Guide pg. 47</Link></p>
<p>As a vampire, you may use your create spawn ability to transform a dire bat, dire rat, or wolf into a more powerful vampiric companion.<br/><strong>Prerequisites:</strong> <Link to="/template/vampire">Vampire</Link>, Charisma 18, <Link to="/ability/animal_companion">animal companion</Link> class ability, sufficiently high level (see below).<br/><strong>Benefit:</strong> A vampire with this feat can elect to use its create spawn ability on an animal summoned using the child of the night ability (such as a <Link to="/monster/dire_bat">dire bat</Link>, <Link to="/monster/dire_rat">dire rat</Link>, or <Link to="/monster/wolf">wolf</Link>) to create a vampiric animal companion. This decision must be made as a free action as the vampire slays the animal with its <Link to="/umr/blood_drain">blood drain</Link> or <Link to="/umr/energy_drain">energy drain</Link> ability. The animal rises from death in 1d4 days as a vampiric animal bonded with the vampire who spawned it. Thereafter, the vampiric animal advances in abilities like a normal <Link to="/sidekick/animal_companion">animal companion</Link> as the vampire gains further class levels in the class that granted the animal companion.</p>
<p>In order to gain a dire rat as a vampiric companion, a vampire's effective druid level must be 4th. To gain a wolf as an vampiric companion, the vampire's effective druid level must be 6th. To gain a dire bat vampiric companion, the vampire's effective druid level must be 9th. At your option, additional animals could be added to this list - use these examples as guides to set minimum levels.</p>
<p>Vampiric animal companions count toward the total number of Hit Dice a vampire may enslave, as well as toward the limit of animal companions the character may have at any one time. Any vampiric animal companion the vampire creates that would exceed such limits becomes a free-willed undead. A vampire may also free a vampiric companion in order to enslave a new one, but once freed, the vampiric animal cannot be enslaved again.</p>
<p>A vampiric animal's statistics are identical to those of the original animal, save for the following changes.</p>
<ul>
<li>Its type changes to undead with the augmented animal subtype.</li>
<li>It gains a +4 natural armor bonus.</li>
<li>It gains the blood drain vampire special attack.</li>
<li>It gains an energy drain attack (1 level, DC equal to 10 + 1/2 the animal companion's racial HD + the animal companion's Charisma modifier).</li>
<li>It gains the dominate vampire special attack with respect to animals of its type.</li>
<li>It gains <Link to="/umr/channel_resistance">channel resistance</Link> +2, DR 5/silver, resist cold and electricity 10, fast healing 2, and the vampire qualities of gaseous form and shadowless.</li>
<li>It gains all of the standard vampire weaknesses.</li>
<li>It gains Str +2, Dex +2, and Cha +4.</li>
<li>It does not gain the vampire's children of the night or create spawn abilities.</li>
</ul>
</>};
const _vampiric_companion = {title: "Vampiric Companion", jsx: <><h2 id="feat-vampiric_companion-vampiric-companion">Vampiric Companion</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 237</Link>, <Link to="/source/blood_of_the_night">Blood of the Night pg. 28</Link></p>
<p>Just as your undead existence mocks nature, so too does your twisted companion reflect the vile nature of vampirism.<br/><strong>Prerequisites:</strong> <Link to="/race/dhampir">Dhampir</Link> or <Link to="/template/vampire">vampire</Link>, nongood alignment, 10th level in a class that grants a familiar or animal companion.<br/><strong>Benefit:</strong> Your animal companion or familiar's type changes to "undead." The creature gains <Link to="/umr/fast_healing">fast healing</Link> 5 as well as your vampire or dhampir weaknesses. If you are a vampire, the creature also gains the following abilities, depending on what type of vampire you are.</p>
<blockquote>
<p><strong className="hl">Jiang-Shi:</strong> While the creature is adjacent to or in your square, it gains the benefit of your prayer scroll ability. The creature crumbles into dust if destroyed (just like a jiang-shi), but is not permanently destroyed unless measures are taken that would destroy a jiang-shi.</p>
<p><strong className="hl">Moroi:</strong> If the creature is adjacent to or in your square when you assume gaseous form, it transforms with you and follows you; its transformation ends when yours does. If reduced to 0 hit points, it's forced into gaseous form and must return to your coffin to reform (or the foot of your coffin if it cannot fit within it).</p>
<p><strong className="hl">Nosferatu:</strong> If the creature is adjacent to or in your square when you assume swarm form, it transforms with you and follows you; its transformation ends when yours does. The creature can climb as if using the spider climb vampire ability, even if its anatomy is not suitable for climbing (such as a <Link to="/monster/horse">horse</Link>).</p>
</blockquote>
<p><strong>Special:</strong> If your animal companion or familiar is destroyed, dismissed, or lost, you can apply the effects of this feat to the replacement creature. If you are destroyed, the creature retains its undead type but loses all other special abilities from this feat. If you have more than one animal companion or familiar, choose one of them when you select this feat and apply its effects to that creature.</p>
<p>You can select this feat more than once. Each time you select the feat, it applies to a different animal companion or familiar.</p>
</>};
const _vandal = {title: "Vandal", jsx: <><h2 id="feat-vandal-vandal">Vandal</h2>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion pg. 25</Link></p>
<p>Even other goblins admire your talent for mindless destruction.<br/><strong>Prerequisites:</strong> <Link to="/race/goblin">Goblin</Link>, <Link to="/ability/sneak_attack">sneak attack</Link> class feature.<br/><strong>Benefit:</strong> You treat unattended objects as if they were vulnerable to your sneak attack, but you only deal half as much damage as you would against an actual creature. For instance, if you rolled 12 extra damage from the sneak attack you would deal an extra 6 damage to the object. This only applies when attacking unattended objects.</p>
</>};
const _vanguard_hustle = {title: "Vanguard Hustle", jsx: <><h2 id="feat-vanguard_hustle-vanguard-hustle-combat">Vanguard Hustle (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 13</Link></p>
<p>You are able to protect allies from a distance.<br/><strong>Prerequisites:</strong> Dex 13, <Link to="/feat/bodyguard">Bodyguard</Link>, <Link to="/feat/combat_patrol">Combat Patrol</Link>, <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, <Link to="/feat/mobility">Mobility</Link>, <Link to="/feat/saving_shield">Saving Shield</Link>, <Link to="/feat/vanguard_style">Vanguard Style</Link>, <Link to="/feat/vanguard_ward">Vanguard Ward</Link>, proficiency with light or heavy shields.<br/><strong>Benefit:</strong> Add half of your shield's enhancement bonus to the shield bonus to AC that you grant to an ally using the Saving Shield feat. While using Vanguard Style, whenever you increase your threatened area with Combat Patrol, your ward retains the bonuses of Vanguard Style as long as he remains within your threatened area, and you can use Bodyguard, Saving Shield, and Vanguard Style whenever an ally that is within this threatened area is the target of an attack.</p>
</>};
const _vanguard_style = {title: "Vanguard Style", jsx: <><h2 id="feat-vanguard_style-vanguard-style-combat-style">Vanguard Style (Combat, Style)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 13</Link></p>
<p>You can bring your shield to bear against dangers that threaten your allies.<br/><strong>Prerequisites:</strong> <Link to="/feat/bodyguard">Bodyguard</Link>, <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, proficiency with light or heavy shields.<br/><strong>Benefit:</strong> While using this style, when an adjacent ally is required to make a Reflex saving throw, you can expend a use of an attack of opportunity to attempt the aid another action to improve your ally's Reflex save. Your ally gains a +2 bonus to all Reflex saves while adjacent to you until the beginning of your next turn.</p>
</>};
const _vanguard_ward = {title: "Vanguard Ward", jsx: <><h2 id="feat-vanguard_ward-vanguard-ward-combat">Vanguard Ward (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 13</Link></p>
<p>You strongly defend your allies.<br/><strong>Prerequisites:</strong> <Link to="/feat/bodyguard">Bodyguard</Link>, <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, <Link to="/feat/vanguard_style">Vanguard Style</Link>, proficiency with light or heavy shields.<br/><strong>Benefit:</strong> While using Vanguard Style, when an adjacent ally is attacked or required to make a Reflex saving throw, you can expend a use of an attack of opportunity to use both Bodyguard and Vanguard Style to protect that ally. You can also lose your shield bonus to AC to grant your ally a shield bonus to AC of the same value for as long as that ally gains a bonus to Reflex saves from Vanguard Style.</p>
</>};
const _vanths_scythe = {title: "Vanth's Scythe", jsx: <><h2 id="feat-vanths_scythe-vanths-scythe">Vanth's Scythe</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_139_the_dead_road">Pathfinder #139: The Dead Road pg. 71</Link></p>
<p>You've seen the reapers many times, and have learned something of their methods.<br/><strong>Prerequisites:</strong> Character level 9th, <Link to="/race/duskwalker">duskwalker</Link>, ghost hunter racial trait.<br/><strong>Benefit:</strong> When you use your ghost hunter racial trait to grant a <Link to="/eq-weapon/scythe">scythe</Link>, <Link to="/eq-weapon/quarterstaff">quarterstaff</Link>, <Link to="/eq-weapon/whip">whip</Link>, or bow the <Link to="/magic-enh/ghost_touch">ghost touch</Link> weapon special ability, you also grant the <Link to="/magic-enh/bane">undead-bane</Link> weapon special ability. You also gain an additional daily use of ghost hunter.</p>
</>};
const _vaporous_potion = {title: "Vaporous Potion", jsx: <><h2 id="feat-vaporous_potion-vaporous-potion">Vaporous Potion</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 17</Link></p>
<p>You know how to brew potions that can be delivered as a gaseous cloud.<br/><strong>Prerequisites:</strong> <Link to="/feat/brew_potion">Brew Potion</Link>.<br/><strong>Benefit:</strong> When you brew a potion, you can brew it in such a way that when exposed suddenly to air and force, it diffuses into a cloud of vapor that can be inhaled. The potion can still be consumed normally, but it can also be delivered by throwing it at another creature as a <Link to="/rule/splash_weapon">splash weapon</Link>. The potion vial has a range increment of 10 feet and is considered an <Link to="/misc/improvised_weapon">improvised weapon</Link>. On impact, the vial breaks and a cloud of barely visible potion vapor fills the square it lands in (this vapor does not obscure normal sight in any way). If a creature is in that square, it gains the benefits of the potion immediately as though it had imbibed the potion.</p>
<p>Otherwise, the vapor persists for 1d3+1 rounds in only that square before dissipating, and the first creature to enter the square before the vapor dissipates gains the potion's benefits. A creature entering the vapor's space can hold its breath to refrain from inhaling the potion. No more than one creature can benefit from a potion's vapor, and if more than one creature is in the potion's space after it is thrown, the potion is wasted and has no effect. The thrown potion deals no damage to creatures or objects it hits. A spell brewed into a potion this way does not use up a higher-level spell slot than the spell's actual level.</p>
<h3 id="feat-vaporous_potion-versatile-brewing">Versatile Brewing</h3>
<p>The above feat allows potion brewers to concoct unusual variations in their potions, altering the potions' effects in strange and useful ways. This feat functions similarly to metamagic feats, though it affects the creation of potions instead of the normal casting of spells. Level limits for potions apply to their level after the application of any relevant metamagic feats (if the feat affects the component spell's level).</p>
<p>Other versatile bewing feats: <Link to="/feat/delayed_potion">Delayed Potion</Link>, <Link to="/feat/healing_potion">Healing Potion</Link>, <Link to="/feat/lengthy_potion">Lengthy Potion</Link>.</p>
</>};
const _variant_prayer_scroll = {title: "Variant Prayer Scroll", jsx: <><h2 id="feat-variant_prayer_scroll-variant-prayer-scroll">Variant Prayer Scroll</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_night">Blood of the Night pg. 29</Link></p>
<p>You have learned the secret to changing the powers granted by your prayer scroll.<br/><strong>Prerequisites:</strong> <Link to="/template/vampire">Jiang-shi</Link>.<br/><strong>Benefit:</strong> You gain the ability to create a different type of prayer scroll. You may create a prayer scroll with this ability by using any strip of parchment and a writing instrument, but doing so requires 10 minutes of uninterrupted work. Swapping your current prayer scroll for a different prepared one is a standard action. When wearing a different prayer scroll, you gain its special abilities, but lose your normal prayer scroll's immunity to spell completion and spell trigger magic items. Your prayer scrolls can be used only by you, and have no effect when used by other jiang-shis. When you choose this feat, select one of the following prayer scroll types.</p>
<blockquote>
<p><strong className="hl">Embalmed Form:</strong> This prayer scroll alters your physical form to how you looked 1 day before your death. Treat this as an <Link to="/spell/alter_self">alter self</Link> spell that affects you regardless of your original or current type; your caster level is equal to your Hit Dice. Your speed increases by 10 feet, but you lose your immunity to trip attacks and your ability to move through <Link to="/rule/difficult_terrain">difficult terrain</Link> unhindered. These effects persist indefinitely as long as you wear the prayer scroll, but end immediately if you use a different prayer scroll or 24 hours after you remove this prayer scroll.</p>
<p><strong className="hl">Enduring Dust:</strong> If you crumble into dust from hit point damage, you reform after 1 round instead of 1 minute. Scattering your dust does not prevent you from reforming as long none of your dust is more than 30 feet from any other part of your dust. Storing a portion of your dust in an air-tight container prevents you from reforming. If you are unable to reform after 1 minute, you are destroyed.</p>
<p><strong className="hl">Positive Energy Immunity:</strong> You become immune to positive channeled energy used to harm undead. This does not protect you against positive energy from other sources such as <em>cure</em> spells or <Link to="/ability/lay_on_hands">lay on hands</Link>.</p>
<p><strong className="hl">Spell Immunity:</strong> The prayer scroll grants you immunity to a spell, as if you were using <Link to="/spell/spell_immunity">spell immunity</Link>. You decide which spell when you create the prayer scroll, and can choose a different spell each time you create a new spell immunity prayer scroll. If you have 15 or more Hit Dice, this functions as <Link to="/spell/greater_spell_immunity">greater spell immunity</Link>. Creating this type of prayer scroll costs 100 gp &times; the spell level of the spell keyed to the scroll.</p>
</blockquote>
<p><strong>Special:</strong> You may select this feat multiple times. Each time you do so, choose another ability granted by the feat.</p>
</>};
const _varisian_tattoo = {title: "Varisian Tattoo", jsx: <><h2 id="feat-varisian_tattoo-varisian-tattoo">Varisian Tattoo</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 289</Link>, <Link to="/source/rise_of_the_runelords_players_guide">Rise of the Runelords Player's Guide pg. 15</Link>, <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 147</Link></p>
<p>You bear intricate tattoos that inspire and empower your natural magic ability. These tattoos mark you as a worker of the ancient traditions of Varisian magic. A Varisian tattoo typically consists of a long string of complex characters from the Thassilonian alphabet.<br/><strong>Prerequisites:</strong> <Link to="/feat/spell_focus">Spell Focus</Link>.<br/><strong>Benefit:</strong> Select a school of magic (other than divination) in which you have Spell Focus - you cast spells from this school at +1 caster level. Additionally, you gain a single spell-like ability usable up to three times per day. The spell-like ability gained (and its Varisian name) are as follows:</p>
<ul>
<li>Abjuration (avidais): <Link to="/spell/resistance">resistance</Link></li>
<li>Conjuration (idolis): <Link to="/spell/acid_splash">acid splash</Link></li>
<li>Enchantment (carnasia): <Link to="/spell/daze">daze</Link></li>
<li>Evocation (ragario): <Link to="/spell/dancing_lights">dancing lights</Link></li>
<li>Illusion (vangloris): <Link to="/spell/ghost_sound">ghost sound</Link></li>
<li>Necromancy (voratalo): <Link to="/spell/touch_of_fatigue">touch of fatigue</Link></li>
<li>Transmutation (avaria): <Link to="/spell/mage_hand">mage hand</Link></li>
</ul>
</>};
const _vast_hatred = {title: "Vast Hatred", jsx: <><h2 id="feat-vast_hatred-vast-hatred-combat">Vast Hatred (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 37</Link></p>
<p>Your rage stretches beyond normal bounds.<br/><strong>Prerequisites:</strong> <Link to="/race/gnome">Gnome</Link>, hatred racial trait.<br/><strong>Benefit:</strong> Select two creature types (and subtypes where appropriate) from the list of potential <Link to="/ability/favored_enemies">favored enemies</Link> from the ranger class ability. Your +1 attack bonus from the hatred racial trait applies to creatures of the selected types (and subtypes).<br/><strong>Special:</strong> You may take this feat more than once. Its benefits do not stack. Each time you select this feat, you select two additional creature types to which your hatred racial trait applies.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-vast_hatred--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-vast_hatred-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>You can spend 5 stamina points to designate a creature type (and subtype, if appropriate) from the Ranger Favored Enemies table. Your attack bonus from the hatred racial trait also applies to creatures of the selected type (and subtype, if appropriate) until the start of your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _vast_spell = {title: "Vast Spell", jsx: <><h2 id="feat-vast_spell-vast-spell-metamagic">Vast Spell (Metamagic)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 5</Link></p>
<p>Your spells cover targets across a larger area.<br/><strong>Prerequisites:</strong> Caster level 3rd.<br/><strong>Benefit:</strong> You can alter a spell that targets a number of creatures no more than 30 feet apart, such as <Link to="/spell/haste">haste</Link>. The maximum distance apart of those you target with the spell increases to 60 feet. A vast spell uses up a spell slot 1 level higher than the spell's actual level.</p>
</>};
const _veiled_contempt = {title: "Veiled Contempt", jsx: <><h2 id="feat-veiled_contempt-veiled-contempt">Veiled Contempt</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_high_court">Heroes of the High Court pg. 18</Link></p>
<p>You are skilled in disguising your dissatisfaction with the current regime or authority.<br/><strong>Prerequisites:</strong> Bluff 3 ranks.<br/><strong>Benefit:</strong> The DC for Sense Motive checks to get a hunch about you is equal to 20 + your ranks in Bluff, instead of the normal 20. If the Sense Motive check is specifically to assess your allegiance or trustworthiness, the DC is equal to 20 + two times your ranks in Bluff.</p>
</>};
const _vengeance = {title: "Vengeance", jsx: <><h2 id="feat-vengeance-vengeance-story">Vengeance (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign pg. 73</Link></p>
<p>The need to avenge those you loved drives you to great deeds.<br/><strong>Prerequisites:</strong> You must have a close family member or other loved one slain by a specific challenging foe or that foe's minions, or have the <Link to="/rule/birth_circumstances_and_more">Raiders (childhood event)</Link> or <Link to="/rule/class_background_tables">Vengeance (barbarian)</Link> background.<br/><strong>Benefit:</strong> You gain a +1 bonus on saving throws, attack rolls, and weapon damage rolls against your chosen foe and known minions of that foe.<br/><strong>Goal:</strong> Thwart your chosen foe.<br/><strong>Completion Benefit:</strong> You gain a +1 bonus on all saving throws. This bonus stacks with this feats's bonus against your foe and its minions, should they survive.</p>
</>};
const _vengeful_banisher = {title: "Vengeful Banisher", jsx: <><h2 id="feat-vengeful_banisher-vengeful-banisher-story">Vengeful Banisher (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook pg. 13</Link></p>
<p>You've witnessed demons and their madness firsthand, likely in one of the lands detailed in this section, or perhaps some other demon-marked region such as the Worldwound or the Abyss. Since then, You've sworn to send these wretched fiends back to whence they came, and You've become an expert at rooting out their kind and their servants.<br/><strong>Prerequisites:</strong> You witnessed at least one family member or a close friend being killed by demons or demonic cultists, or you have the Hated Foe (barbarian) or An Eye for an Eye (ranger) <Link to="/rule/class_background_tables">class background</Link>.<br/><strong>Benefit:</strong> You gain a +2 bonus on saving throws against spells or effects originating from demon worshipers and from creatures of the demon type.<br/><strong>Goal:</strong> Convince the leader of a demon cult to renounce her Abyssal lord and seek atonement for her actions. Alternatively, if you kill the cult leader, you must also decisively defeat at least half of the cultists and have the cult's base of operations consecrated by a well-known local priest.<br/><strong>Completion Benefit:</strong> When a demon damages you with an attack, spell, spell-like ability, or special ability and reduces you to fewer than 0 hit points, you may allow righteous energy to pour through you and into the demon, instantly sending it to another plane of existence (as <Link to="/spell/dismissal">dismissal</Link>) if it fails a Will save (DC = 10 + 1/2 your Hit Dice + your Charisma modifier). This <em>dismissal</em> takes place after you are damaged but before you fall unconscious, so you can use this ability even if the demon kills you. You can use this ability once per day. Once you have used this ability, you must be healed to your maximum number of hit points before you can use the ability again.</p>
</>};
const _vengeful_death_vow = {title: "Vengeful Death Vow", jsx: <><h2 id="feat-vengeful_death_vow-vengeful-death-vow">Vengeful Death Vow</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_worldscape_1">Pathfinder Worldscape #1 pg. 28</Link></p>
<p>Your death vow strikes terror into the hearts of your enemies, making them less likely to hit you in combat.<br/><strong>Prerequisites:</strong> Death vow class feature.<br/><strong>Benefit:</strong> Targets of your death vow take a -2 penalty on attacks made against you.</p>
</>};
const _venomous_spray = {title: "Venomous Spray", jsx: <><h2 id="feat-venomous_spray-venomous-spray-combat">Venomous Spray (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 200</Link></p>
<p>You can spit your poison into a nearby opponent's face.<br/><strong>Prerequisites:</strong> <Link to="/monster/serpentfolk">Serpentfolk</Link>.<br/><strong>Benefit:</strong> You can spit venom as a secondary ranged attack with a range of 5 feet. This is a natural attack and doesn't provoke attacks of opportunity. A target struck by your venom must succeed at a Fortitude save (DC = your poison DC) or be <Link to="/misc/blinded">blinded</Link> for 1d4 rounds and suffer the normal effects of your poison. You can't use this attack during any round in which you make a bite attack (and vice versa). After spitting venom, you are unable to use your poisonous bite or to spit venom for 1d4 rounds.</p>
</>};
const _venomous_stare = {title: "Venomous Stare", jsx: <><h2 id="feat-venomous_stare-venomous-stare-stare">Venomous Stare (Stare)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast pg. 17</Link></p>
<p>Your stare is toxic to your enemies.<br/><strong>Prerequisites:</strong> <Link to="/class/mesmerist">Mesmerist</Link> level 11th, painful stare class feature.<br/><strong>Benefit:</strong> When you trigger your painful stare, the target immediately becomes envenomed by the following poison:</p>
<div className="sideNoteWrap"><ScrollContainer id="feat-venomous_stare--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={9} to="/rule/poison"><IonIcon aria-label="Poison" icon="/icons/poison-bottle.svg" /></ThLink><th colSpan={4} scope="col" className="title">Painful Stare</th></tr><tr><th scope="row">Type</th><td colSpan={3}>Injury</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Fort 10 + 1/2 your mesmerist level + your Cha modifier</td></tr><tr><th scope="row">Onset</th><td colSpan={3}>immediate</td></tr><tr><th scope="row">Frequency</th><td colSpan={3}>1/round for 6 rounds</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>1d3 <Link to="/rule/dex_damage">Dex damage</Link></td></tr><tr><th scope="row">Cure</th><td colSpan={3}>2 saves</td></tr></tbody></table></ScrollContainer></div><p>Whether your target succeeds at or fails its save, you can't use Venomous Stare against that particular foe for 24 hours.</p>
</>};
const _verbose_performer = {title: "Verbose Performer", jsx: <><h2 id="feat-verbose_performer-verbose-performer-faction">Verbose Performer (Faction)</h2>
<p><strong>Sources</strong> <Link to="/source/faction_guide">Faction Guide pg. 58</Link></p>
<p>The range of your bardic performances increases.<br/><strong>Prerequisites:</strong> <Link to="/ability/bardic_performance">Bardic performance</Link> class feature, <Link to="/feat/extra_performance">Extra Performance</Link>, <Link to="/feat/master_performer">Master Performer</Link>, <Link to="/class/bard">bard</Link> level 8th, <Link to="/rule/kitharodian_academy">Kitharodian Academy</Link> 15 TPA.<br/><strong>Benefit:</strong> Double the range of any bardic performance ability that possesses a range in the ability description.</p>
</>};
const _verdant_spell = {title: "Verdant Spell", jsx: <><h2 id="feat-verdant_spell-verdant-spell-metamagic">Verdant Spell (Metamagic)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 119</Link>, <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 26</Link></p>
<p>Your magical connection to nature allows you to entice, fool, and misdirect plants and fungi as though they were people.<br/><strong>Prerequisites:</strong> <Link to="/feat/spell_focus">Spell Focus</Link> (enchantment), Knowledge (nature) 6 ranks.<br/><strong>Benefit:</strong> A verdant spell affects plant creatures (even mindless plant creatures) as if they weren't immune to mind-affecting effects, but it has no effect on other types of creatures. A verdant spell uses up a spell slot 2 levels higher than the spell's actual level. This feat works only on mind-affecting spells.<br/><strong>Normal:</strong> Creatures of the plant type are immune to mind-affecting effects.</p>
</>};
const _verdant_step = {title: "Verdant Step", jsx: <><h2 id="feat-verdant_step-verdant-step">Verdant Step</h2>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins pg. 15</Link></p>
<p>You can travel between magic plants and plants with which you have an affinity.<br/><strong>Prerequisites:</strong> Con 13, character level 7th, plant type.<br/><strong>Benefit:</strong> Once per day, you can step into an adjacent plant with which you share affinity, then exit from a plant of the same kind. This functions as <Link to="/spell/tree_stride">tree stride</Link> with the following changes: the duration is 1 round; the transport range is 200 feet per character level; transporting yourself is a standard action; and a <Link to="/race/ghoran">ghoran</Link> using this ability can pass through any living tree, while a <Link to="/race/vine_leshy">vine leshy</Link> can pass through any living vine. You can also enter any magically created or enhanced plants, such as those produced by <Link to="/spell/wall_of_thorns">wall of thorns</Link> or plants affected by <Link to="/spell/entangle">entangle</Link>, then exit from either another similar plant or a plant with which you have an affinity.<br/><strong>Special:</strong> The GM determines plant affinity for non-ghoran and non-vine leshy plant creatures.</p>
</>};
const _verify = {title: "Verify", jsx: <><h2 id="feat-verify-verify">Verify</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 16</Link></p>
<p>Those whom you catch breaking a deal are more subject to your powers.<br/><strong>Prerequisites:</strong> Ability to cast 1st-level spells, lawful evil alignment, worshiper of <Link to="/faith/asmodeus">Asmodeus</Link>.<br/><strong>Benefit:</strong> You gain a +5 bonus on Sense Motive checks to determine whether a creature is lying when you ask if it has followed the terms of a contract or deal to which it formally agreed. This includes all written and signed contracts, but also such things as witnessed oaths of loyalty and guild charters.</p>
<p>If you succeed at such a Sense Motive check and learn that a creature has violated any part of such a formal bargain, that creature takes a -2 penalty on saving throws against your spells, spell-like abilities, and supernatural abilities.</p>
</>};
const _vermin_heart = {title: "Vermin Heart", jsx: <><h2 id="feat-vermin_heart-vermin-heart">Vermin Heart</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 173</Link>, <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 219</Link>, <Link to="/source/revenge_of_the_kobold_king">Revenge of the Kobold King pg. 6</Link></p>
<p>You have a special bond with things that creep, crawl, skitter, and sting.<br/><strong>Prerequisites:</strong> <Link to="/ability/wild_empathy">Wild empathy</Link> class feature.<br/><strong>Benefit:</strong> You may target vermin with spells and special abilities that only affect animals (although they are still affected by spells targeting vermin as well). You may use wild empathy to influence vermin as easily as you influence animals.</p>
</>};
const _versatile_channeler = {title: "Versatile Channeler", jsx: <><h2 id="feat-versatile_channeler-versatile-channeler">Versatile Channeler</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 159</Link></p>
<p>You can choose to channel positive and negative energy.<br/><strong>Prerequisites:</strong> <Link to="/ability/channel_energy">Channel energy</Link> class feature, necromancer or neutrally aligned cleric (see below).<br/><strong>Benefit:</strong> You may make a choice whenever you use your channel energy class feature.</p>
<p>If you normally channel positive energy, you may choose to channel negative energy as if your effective cleric level were 2 levels lower than normal.</p>
<p>If you normally channel negative energy, you may choose to channel positive energy as if your effective cleric level were 2 levels lower than normal.</p>
<p>Having this feat means you qualify for feats and abilities that have "channel positive energy" or "channel negative energy" as a prerequisite (for example, you qualify for the <Link to="/feat/command_undead">Command Undead</Link> feat and the <Link to="/feat/turn_undead">Turn Undead</Link> feat).</p>
<p><strong>Note:</strong> This feat only applies to necromancers, neutral clerics who worship neutral deities, or neutral clerics who do not worship a deity - characters who have the channel energy class ability and have to make a choice to channel positive or negative energy at 1st level. Clerics whose alignment or deity makes this choice for them cannot select this feat.</p>
</>};
const _versatile_jinx = {title: "Versatile Jinx", jsx: <><h2 id="feat-versatile_jinx-versatile-jinx">Versatile Jinx</h2>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion pg. 27</Link></p>
<p>Your jinx's power comes from a different source than most halflings.<br/><strong>Prerequisites:</strong> <Link to="/feat/iron_will">Iron Will</Link>, Halfling Jinx trait.<br/><strong>Benefit:</strong> Choose either Intelligence or Wisdom. The DC of your jinx is based on this ability score instead of on Charisma.</p>
</>};
const _versatile_spontaneity = {title: "Versatile Spontaneity", jsx: <><h2 id="feat-versatile_spontaneity-versatile-spontaneity">Versatile Spontaneity</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 9</Link></p>
<p>You made a good name for yourself in the <Link to="/rule/pathfinder_society">Pathfinder Society</Link> in part because you knew how to prepare for the challenges before you, even if your natural magical abilities lend themselves less to preparation and more to spontaneity.<br/><strong>Prerequisites:</strong> Int 13 or Wis 13 (see Special), ability to spontaneously cast 2nd-level spells.<br/><strong>Benefit:</strong> When you regain spell slots at the start of the day, you may opt to prepare one spell you don't know in place of a daily spell slot 1 level higher than the prepared spell's level. To do so, you must have access to the selected spell on a scroll or in a spellbook, and the spell must be on your spell list (even if it is not one of your spells known). This process takes 10 minutes per spell level of the selected spell. You can cast the selected spell a single time, expending the spell slot as though it were a known spell being cast by you. Preparing a spell in this manner expends a scroll but not a spellbook. A spell prepared in this way is considered its actual level rather than the level of the spell slot expended. You can apply metamagic feats to the spell as normal, as long as the spell's actual level plus the increases from metamagic feats is 1 level lower than the highest-level spell you can cast. For example, a 12th-level sorcerer with this feat, a scroll of <Link to="/spell/fireball">fireball</Link>, and the <Link to="/feat/empower_spell">Empower Spell</Link> metamagic feat could prepare an empowered <em>fireball</em> spell in her 6th-level spell slot.<br/><strong>Special:</strong> If you spontaneously cast arcane spells, you must have an Intelligence score of at least 13 to take this feat. If you spontaneously cast divine spells, you must have a Wisdom score of at least 13 to take this feat. If you have both arcane and divine spellcasting classes, you can use this feat to prepare a spell using a given class's spell slot as long as you meet the associated ability score prerequisite.</p>
</>};
const _versatile_summon_monster = {title: "Versatile Summon Monster", jsx: <><h2 id="feat-versatile_summon_monster-versatile-summon-monster">Versatile Summon Monster</h2>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook pg. 18</Link></p>
<p>You've learned to summon a more diverse array of monsters.<br/><strong>Prerequisites:</strong> Knowledge (arcana) 1 rank, Knowledge (planes) 1 rank.<br/><strong>Benefit:</strong> Pick any two templates from the following list: <Link to="/template/aerial">aerial</Link>, <Link to="/template/aqueous">aqueous</Link>, <Link to="/template/chthonic">chthonic</Link>, <Link to="/template/dark">dark</Link>, <Link to="/template/fiery">fiery</Link>, or <Link to="/template/primordial">primordial</Link>. When you summon one or more creatures that would normally be available with the <Link to="/template/celestial">celestial</Link>, <Link to="/template/entropic">entropic</Link>, <Link to="/template/fiendish">fiendish</Link>, or <Link to="/template/resolute">resolute</Link> template using a <Link to="/spell/summon_monster">summon monster</Link> spell (or an effect that mimics such a spell), you can instead apply one of the chosen templates to each creature. You can apply a different template to each creature you summon.<br/><strong>Special:</strong> You can select this feat more than once. Each time you do, you can choose an additional two templates.</p>
</>};
const _versatile_summon_natures_ally = {title: "Versatile Summon Nature's Ally", jsx: <><h2 id="feat-versatile_summon_natures_ally-versatile-summon-natures-ally">Versatile Summon Nature's Ally</h2>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook pg. 18</Link></p>
<p>You've learned to summon a wider array of creatures.<br/><strong>Prerequisites:</strong> <Link to="/feat/augment_summoning">Augment Summoning</Link>, Knowledge (nature) 1 rank, Knowledge (planes) 1 rank.<br/><strong>Benefit:</strong> When you summon one or more animals, humanoids, or vermin using a <Link to="/spell/summon_natures_ally">summon nature's ally</Link> spell (or an effect that mimics such a spell), instead of granting them the benefit from Augment Summoning, you can instead apply one of the following templates to them: <Link to="/template/aerial">aerial</Link>, <Link to="/template/aqueous">aqueous</Link>, <Link to="/template/chthonic">chthonic</Link>, <Link to="/template/fiery">fiery</Link>, or <Link to="/template/primordial">primordial</Link>. If you summon multiple creatures with one casting, they must all have the same template.</p>
</>};
const _vestigial_head = {title: "Vestigial Head", jsx: <><h2 id="feat-vestigial_head-vestigial-head">Vestigial Head</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 153</Link></p>
<p>You were born with a parasitic vestigial head with its own stunted brain. The head may be mostly subsumed within your own flesh and visible only as a distorted face, or it might sprout out of its own neck from your neck, shoulder, back, or chest.<br/><strong>Prerequisites:</strong> <Link to="/monster/ogre">Ogre</Link>.<br/><strong>Benefit:</strong> Anytime you must attempt a Will save against a hostile effect, there is a 25% change that the effect targets your vestigial head instead. If this occurs, you are treated as if you had succeeded at your saving throw, and instead are <Link to="/misc/sickened">sickened</Link> for 1d4 rounds or the duration of the effect (whichever is longer).<br/><strong>Special:</strong> You can take this feat twice. The second time you do, the chance of a hostile Will effect targeting your vestigial head instead of your own increases to 50%. This doesn't give you another vestigial head.</p>
</>};
const _vicious_stomp = {title: "Vicious Stomp", jsx: <><h2 id="feat-vicious_stomp-vicious-stomp-combat">Vicious Stomp (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 123</Link></p>
<p>You take advantage of the moment to brutally kick an enemy when he is down.<br/><strong>Prerequisites:</strong> <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>.<br/><strong>Benefit:</strong> Whenever an opponent falls <Link to="/rule/prone">prone</Link> adjacent to you, that opponent provokes an attack of opportunity from you. This attack must be an unarmed strike.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-vicious_stomp--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-vicious_stomp-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>When an opponent provokes an unarmed strike attack of opportunity from you by falling prone, you can spend 2 stamina points to deal an additional 1d6 points of damage with that unarmed strike.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _victory_through_unity = {title: "Victory Through Unity", jsx: <><h2 id="feat-victory_through_unity-victory-through-unity-story">Victory Through Unity (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_131_the_reapers_right_hand">Pathfinder #131: The Reaper's Right Hand pg. 79</Link></p>
<p>You have practiced your family's genetic experimentations upon your own familiar.<br/><strong>Prerequisites:</strong> You must have a familiar, and you must either be a member of House Merrosett or have the Initiated (witch) or Storied Lineage (wizard) <Link to="/rule/class_background_tables">background</Link>.<br/><strong>Benefit:</strong> When you gain this feat, choose an animal aspect granted by the hunter's <Link to="/ability/animal_focus">animal focus</Link> class ability and apply it to your familiar. Your hunter level for this ability is 1st, and you cannot change this ability once you have selected it. If your familiar dies, it loses its aspect and you may choose a new aspect if you take a new familiar. Your familiar's form is altered by superficial changes appropriate to its aspect.<br/><strong>Goal:</strong> You must breed a new magical creature.<br/><strong>Completion Benefit:</strong> You may either choose and apply a second animal aspect to your familiar or apply an evolution from the 1-point <Link to="/ability/evolutions">evolutions</Link> available to a summoner's eidolon. The familiar must conform to any limitations of the evolution (such as being one size category larger than its rider to serve as a mount). Once selected, this decision cannot be changed, but if your familiar dies it loses these abilities and you may choose new abilities if you take a new familiar. If your familiar breeds with its original kind, it has the potential to pass on these extra abilities as permanent traits.</p>
</>};
const _vigilant_charger = {title: "Vigilant Charger", jsx: <><h2 id="feat-vigilant_charger-vigilant-charger-combat">Vigilant Charger (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 119</Link></p>
<p>You can ready yourself to spring an attack against your enemies at a moment's notice.<br/><strong>Prerequisites:</strong> Str 13, Dex 13, <Link to="/feat/combat_reflexes">Combat Reflexes</Link>.<br/><strong>Benefit:</strong> You can <Link to="/rule/ready_an_action">ready an action</Link> to <Link to="/rule/charge">charge</Link> when an enemy enters a specific space you designate. You must be able to charge the square both when you ready the charge and when the readied action triggers, or you cannot attempt the readied action. When you make a readied charge, you can move only up to your speed.<br/><strong>Normal:</strong> You can't ready an action to charge. Charging allows you to move up to twice your speed.</p>
</>};
const _vigilant_eidolon = {title: "Vigilant Eidolon", jsx: <><h2 id="feat-vigilant_eidolon-vigilant-eidolon">Vigilant Eidolon</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 159</Link></p>
<p>Your eidolon is highly observant, and its link with you increases your own watchfulness.<br/><strong>Prerequisites:</strong> Eidolon class feature.<br/><strong>Benefit:</strong> While your eidolon is within your reach, you gain a +4 bonus on Perception checks. If you have 10 or more ranks in Perception, this bonus increases to +8. This does not apply if your eidolon is helpless or unconscious.</p>
</>};
const _vigilant_phantom = {title: "Vigilant Phantom", jsx: <><h2 id="feat-vigilant_phantom-vigilant-phantom">Vigilant Phantom</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 141</Link></p>
<p>Your phantom is highly observant, and its link with you increases your own watchfulness.<br/><strong>Prerequisites:</strong> Phantom class feature.<br/><strong>Benefit:</strong> While your <Link to="/sidekick/phantom">phantom</Link> is within your reach, you gain a +4 bonus on Perception checks. If you have 10 or more ranks in Perception, this bonus increases to +8. This doesn't apply if your phantom is helpless or unconscious.</p>
</>};
const _vile_leadership = {title: "Vile Leadership", jsx: <><h2 id="feat-vile_leadership-vile-leadership">Vile Leadership</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 135</Link>, <Link to="/source/champions_of_corruption">Champions of Corruption pg. 14</Link></p>
<p>You rule over your own cabal of minions with a villainous cohort as your lieutenant.<br/><strong>Prerequisites:</strong> Any evil alignment, character level 7th.<br/><strong>Benefit:</strong> You can attract a loyal cohort and a number of intimidated followers to assist in your nefarious deeds. This feat is similar to <Link to="/feat/leadership">Leadership</Link>, except Vile Leadership rewards - rather than punishes - leaders with cruel reputations or who cause their followers' deaths. Once you take this feat, you cannot take the Leadership feat without retraining your feat selection. Numerous factors can affect your Vile Leadership score (which acts as a Leadership score for the purpose of feats and abilities that rely on a Leadership score, other than Leadership itself); work in conjunction with your GM and use the tables below to adjust your Vile Leadership score accordingly. The NPCs you attract must be of a nongood alignment.</p>
<p><strong className="hl">Vile Leadership Modifiers:</strong> Your reputation (from the point of view of the cohort or follower you are trying to attract) raises or lowers your Vile Leadership score.</p>
<ScrollContainer id="feat-vile_leadership--table-0"><table>
<thead>
<tr>
<th>Leader's Reputation</th>
<th>Modifier</th>
</tr>
</thead>
<tbody><tr>
<td>Ruthless</td>
<td>+2</td>
</tr>
<tr>
<td>Rewards loyalty or success</td>
<td>+1</td>
</tr>
<tr>
<td>Possesses a special power</td>
<td>+1</td>
</tr>
<tr>
<td>Indecisive</td>
<td>-1</td>
</tr>
<tr>
<td>Tolerant of failure</td>
<td>-1</td>
</tr>
<tr>
<td>Merciful</td>
<td>-2</td>
</tr>
</tbody></table></ScrollContainer>
<p>Other modifiers may apply when you try to attract a cohort with this feat, as listed below.</p>
<ScrollContainer id="feat-vile_leadership--table-1"><table>
<thead>
<tr>
<th>Leader's Attributes</th>
<th>Modifer</th>
</tr>
</thead>
<tbody><tr>
<td>Gained power by eliminating a superior</td>
<td>+1</td>
</tr>
<tr>
<td>Fails to punish or kill minions who make costly mistakes</td>
<td>-2<sup><InnerLink showBacklink="backlink-feat-vile_leadership-ref-C-1" id="feat-vile_leadership-ref-C-1" data-hash-target to="feat-vile_leadership-C">1</InnerLink></sup></td>
</tr>
<tr>
<td>Recruits a cohort of a different alignment</td>
<td>-1</td>
</tr>
</tbody></table></ScrollContainer>
<p>Followers have different priorities from cohorts. When you try to attract a follower, use the following modifiers.</p>
<ScrollContainer id="feat-vile_leadership--table-2"><table>
<thead>
<tr>
<th>Leader's Attributes</th>
<th>Modifier</th>
</tr>
</thead>
<tbody><tr>
<td>Has a stronghold, base of operations, guildhouse, etc.</td>
<td>+2</td>
</tr>
<tr>
<td>Has punished or killed minions to set an example or assert dominance</td>
<td>+1<sup><InnerLink showBacklink="backlink-feat-vile_leadership-ref-B-1" id="feat-vile_leadership-ref-B-1" data-hash-target to="feat-vile_leadership-B">2</InnerLink></sup></td>
</tr>
<tr>
<td>Has a tendency toward long periods of inactivity</td>
<td>-1</td>
</tr>
<tr>
<td>Restricts minions from looting, pillaging, or pursing other spoils of war</td>
<td>-1</td>
</tr>
</tbody></table></ScrollContainer>
<section data-footnotes>
<h3 id="feat-vile_leadership-label">Footnotes</h3>
<ol>
<li id="feat-vile_leadership-C">
<p>Cumulative per incident of compassion shown. This penalty is incurred even if you show mercy to avoid killing or punishing more than 20% of your minions during a given character level. <InnerLink id="backlink-feat-vile_leadership-ref-C-1" data-hash-target to="feat-vile_leadership-ref-C-1" aria-label="Back to reference C-1">↩</InnerLink></p>
</li>
<li id="feat-vile_leadership-B">
<p>Cumulative to a maximum bonus of +1 per character level. If you punish or kill more than 20% of your minions during a given character level, this bonus becomes a penalty instead. When you gain a new level, any bonus or penalty from punishing or killing minions resets to 0. <InnerLink id="backlink-feat-vile_leadership-ref-B-1" data-hash-target to="feat-vile_leadership-ref-B-1" aria-label="Back to reference B-1">↩</InnerLink></p>
</li>
</ol>
</section>
</>};
const _vim_and_vigor = {title: "Vim and Vigor", jsx: <><h2 id="feat-vim_and_vigor-vim-and-vigor-combat">Vim and Vigor (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook pg. 15</Link></p>
<p>You rebound more quickly than normal when you draw upon your inner reserve to repair your wounds.<br/><strong>Prerequisites:</strong> Con 13, <Link to="/feat/combat_vigor">Combat Vigor</Link>, <Link to="/feat/endurance">Endurance</Link>, character level 3rd.<br/><strong>Benefit:</strong> Your vigor pool gains 1 vigor point. The <Link to="/misc/fatigued">fatigued</Link> condition that you gain from spending vigor points (as described by the Combat Vigor feat) lasts for 3 rounds instead of 1 minute. In addition, when you take this feat, you gain a +2 bonus on saving throws against effects that cause fatigue or <Link to="/misc/exhaustion">exhaustion</Link>.</p>
</>};
const _vindictive_fall = {title: "Vindictive Fall", jsx: <><h2 id="feat-vindictive_fall-vindictive-fall">Vindictive Fall</h2>
<p><strong>Sources</strong> <Link to="/source/antiheros_handbook">Antihero's Handbook pg. 9</Link></p>
<p>When you fall, you drag others down with you.<br/><strong>Prerequisites:</strong> <Link to="/feat/lightning_reflexes">Lightning Reflexes</Link>.<br/><strong>Benefit:</strong> When a creature causes you to fall <Link to="/rule/prone">prone</Link>, such as with an effect or a spell (such as <Link to="/spell/grease">grease</Link>) or by succeeding at a combat maneuver to <Link to="/rule/trip">trip</Link> you, you can attempt a combat maneuver check as an immediate action to trip an enemy within your melee reach. The target of this combat maneuver need not be the creature that caused you to fall prone. If you do not have the <Link to="/feat/improved_trip">Improved Trip</Link> feat or a similar ability, your trip combat maneuver provokes an attack of opportunity from the target as normal.</p>
</>};
const _violent_display = {title: "Violent Display", jsx: <><h2 id="feat-violent_display-violent-display-combat">Violent Display (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 23</Link></p>
<p>You never miss an opportunity to cow foes.<br/><strong>Prerequisites:</strong> <Link to="/feat/dazzling_display">Dazzling Display</Link>, <Link to="/feat/weapon_focus">Weapon Focus</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> When you land a successful sneak attack or confirm a critical hit against a creature with a weapon with which you have Weapon Focus, you can use Dazzling Display as an immediate action.</p>
</>};
const _virtuous_creed = {title: "Virtuous Creed", jsx: <><h2 id="feat-virtuous_creed-virtuous-creed">Virtuous Creed</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 16</Link></p>
<p>You accept a creed to guide your destiny toward good.<br/><strong>Prerequisites:</strong> You must be good.<br/><strong>Benefit:</strong> Select one of the following virtues. You must adhere to that virtue's creed in order to benefit from its bonus. If you break any part of the creed, you are unable to gain the benefits from that virtue for 24 hours. Significant violations require atonement for you to be able to benefit from this feat again.<br/><strong>Special:</strong> You can gain this feat multiple times. Each time you take this feat, you must choose a new virtue.</p>
<h3 id="feat-virtuous_creed-humility">Humility</h3>
<p><strong>Creed:</strong> You must always show respect to others. You must put your own desires aside in favor of the needs of the masses. You must be conservative in dress and in actions, and wary not to display pride or gloat about your wealth or achievements.<br/><strong>Benefit:</strong> You add your Wisdom modifier on Diplomacy checks in addition to your Charisma modifier.</p>
<h3 id="feat-virtuous_creed-courage">Courage</h3>
<p><strong>Creed:</strong> You can never willingly flee combat when others' lives are at risk. You must never show cowardice in sight of your enemies.<br/><strong>Benefit:</strong> When <Link to="/misc/shaken">shaken</Link>, you gain a +3 bonus on Will saves against any effects that would worsen your condition to <Link to="/misc/frightened">frightened</Link> or <Link to="/misc/panicked">panicked</Link>.</p>
<h3 id="feat-virtuous_creed-freedom">Freedom</h3>
<p><strong>Creed:</strong> You must always seek to ensure that beings have the right to live their lives as their own. You must put an end to slavery when you see it, and break whatever chains hold others down, be they metaphysical or real.<br/><strong>Benefit:</strong> Once per day, you can reroll a Will save against a charm or compulsion effect and gain a +2 bonus on that reroll. You must decide to use this ability before the results are revealed. You must take the second roll, even if it is worse.</p>
<h3 id="feat-virtuous_creed-purity">Purity</h3>
<p><strong>Creed:</strong> You must refrain from contact with unclean things and keep your thoughts unpolluted. You must not touch evil-aligned weapons or creatures. You must practice clean eating, ingesting only properly prepared foods that strengthen the body and mind.<br/><strong>Benefit:</strong> You gain a +2 bonus on all Fortitude saving throws against disease or poison. In addition, the onset time for any disease or poison is doubled.</p>
<h3 id="feat-virtuous_creed-protection">Protection</h3>
<p><strong>Creed:</strong> You must always stand up for those weaker than yourself. You must defend your community against those that prey upon it.<br/><strong>Benefit:</strong> When you use the aid another action to improve an ally's AC against attacks, the bonus increases to +4 instead of +2.</p>
<h3 id="feat-virtuous_creed-mercy">Mercy</h3>
<p><strong>Creed:</strong> You must always accept an enemy's surrender. When your enemies are defeated in battle, you must attempt to stabilize them to the best of your ability. You must never bring undue suffering to those who are innocent.<br/><strong>Benefit:</strong> When using a weapon that deals lethal damage to instead deal nonlethal damage, you take no penalty on your attack roll.</p>
</>};
const _virulent_venom = {title: "Virulent Venom", jsx: <><h2 id="feat-virulent_venom-virulent-venom-combat">Virulent Venom (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 5</Link></p>
<p>The poison that drips from your fangs is potent enough to burn through flesh and wood.<br/><strong>Prerequisites:</strong> <Link to="/feat/spit_venom">Spit Venom</Link>, <Link to="/race/nagaji">nagaji</Link>.<br/><strong>Benefit:</strong> Your ability to spit poison granted by the Spit Venom feat deals 1d6 points of acid damage plus an additional 1d6 points of acid damage for every 3 Hit Dice you have, in addition to all other effects. This additional damage affects creatures even if they are immune to poison or succeed at their Fortitude saving throws. In addition, you gain one additional use per day of the ability to spit poison granted by the Spit Venom feat.</p>
</>};
const _visceral_threat = {title: "Visceral Threat", jsx: <><h2 id="feat-visceral_threat-visceral-threat-combat">Visceral Threat (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 21</Link></p>
<p>Your ability to threaten foes is great enough to make them hesitate.<br/><strong>Prerequisites:</strong> <Link to="/feat/intimidating_prowess">Intimidating Prowess</Link>.<br/><strong>Benefit:</strong> You may use Intimidate, rather than Bluff, to attempt a <Link to="/rule/feint">feint</Link> against a creature within your melee reach.</p>
</>};
const _viscous_venom = {title: "Viscous Venom", jsx: <><h2 id="feat-viscous_venom-viscous-venom-combat">Viscous Venom (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 5</Link></p>
<p>Your venom is abnormally thick and adhesive.<br/><strong>Prerequisites:</strong> <Link to="/feat/spit_venom">Spit Venom</Link>, <Link to="/race/nagaji">nagaji</Link>.<br/><strong>Benefit:</strong> When you spit poison using the ability granted by the Spit Venom feat, you can spit a glob of venomous goo at an enemy within 30 feet. Once struck, the target is both exposed to your nagaji poison as normal and entangled. An entangled target can break free from the sticky goo with a successful DC 15 Strength or Escape Artist check as a full-round action or by dealing 15 points of damage to the gooey substance with a slashing weapon. In addition, you gain one additional use per day of the ability to spit poison granted by the Spit Venom feat.</p>
</>};
const _vishkanya_perfume = {title: "Vishkanya Perfume", jsx: <><h2 id="feat-vishkanya_perfume-vishkanya-perfume">Vishkanya Perfume</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 224</Link></p>
<p>You can change your toxic spittle into poisonous breath.<br/><strong>Prerequisites:</strong> <Link to="/feat/deadly_kiss">Deadly Kiss</Link>, toxic racial trait, <Link to="/race/vishkanya">vishkanya</Link>.<br/><strong>Benefit:</strong> As a swift action, you can expend one use of your toxic racial trait to alter your venom into an inhaled poison for 1d4 rounds. At one point within this duration, you can select one adjacent enemy to be exposed. In its inhaled form, your venom is an invisible, perfumed gas, and its DC is 2 lower.</p>
<p>In addition, you can use your toxic racial trait one additional time per day.</p>
<p><strong>Normal:</strong> Vishkanya venom is an injury poison</p>
</>};
const _vision_mastery = {title: "Vision Mastery", jsx: <><h2 id="feat-vision_mastery-vision-mastery-item-mastery">Vision Mastery (Item Mastery)</h2>
<p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 27</Link></p>
<p>You can pierce invisibility with divination magic items.<br/><strong>Prerequisites:</strong> Use Magic Device 2 ranks, base Fortitude save bonus +4.<br/><strong>Benefit:</strong> You can cause an item that has a divination spell of 1st level or higher in its construction requirements to cast either <Link to="/spell/darkvision">darkvision</Link> or <Link to="/spell/see_invisibility">see invisibility</Link>. You can use this feat once per day, plus an additional time per day at base Fortitude save bonus +6, +8, +10, and +12.</p>
</>};
const _vital_strike = {title: "Vital Strike", jsx: <><h2 id="feat-vital_strike-vital-strike-combat">Vital Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 136</Link></p>
<p>You make a single attack that deals significantly more damage than normal.<br/><strong>Prerequisites:</strong> Base attack bonus +6.<br/><strong>Benefit:</strong> When you use the attack action, you can make one attack at your highest base attack bonus that deals additional damage. Roll the weapon's damage dice for the attack twice and add the results together before adding bonuses from Strength, weapon abilities (such as <Link to="/magic-enh/flaming">flaming</Link>), precision based damage, and other damage bonuses. These extra weapon damage dice are not multiplied on a critical hit, but are added to the total.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-vital_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-vital_strike-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>After rolling the damage of a Vital Strike attack, you can spend 2 stamina points to reroll up to two of the weapon's damage dice. (For weapons with more than one damage die, count all the weapon's base damage dice together as one.) You must take the second result, even if it's lower.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-vital_strike--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Vital Strike</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 77</Link><br/>You can strike your foes with incredible force.<br/><strong>Prerequisites:</strong> Vital Strike.<br/><strong>Benefit:</strong> Whenever you use Vital Strike, <Link to="/feat/improved_vital_strike">Improved Vital Strike</Link>, or <Link to="/feat/greater_vital_strike">Greater Vital Strike</Link>, multiply the Strength bonus, magic bonus, and other bonuses that would normally be multiplied on a critical hit by the number of weapon damage dice you roll for that feat.</p>
<p>Extra damage from sources that wouldn't normally be multiplied on a critical hit isn't multiplied by this feat.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _voice_of_beasts = {title: "Voice of Beasts", jsx: <><h2 id="feat-voice_of_beasts-voice-of-beasts">Voice of Beasts</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 119</Link></p>
<p>Your deep connection with nature allows you to speak with all manner of living creatures.<br/><strong>Prerequisites:</strong> Wild shape class feature.<br/><strong>Benefit:</strong> While you are using wild shape, you gain the ability to communicate with all animals. This acts as <Link to="/spell/speak_with_animals">speak with animals</Link>, though the effect is supernatural in nature and can't be dispelled.</p>
</>};
const _voice_of_the_sibyl = {title: "Voice of the Sibyl", jsx: <><h2 id="feat-voice_of_the_sibyl-voice-of-the-sibyl">Voice of the Sibyl</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 159</Link></p>
<p>Your voice is strangely compelling.<br/><strong>Prerequisites:</strong> Cha 15.<br/><strong>Benefit:</strong> You get a +1 bonus on all Bluff, Diplomacy, and Perform (oratory) skill checks. If you have 10 or more ranks in one of these skills, the bonus increases to +3 for that skill. You do not get these bonuses if you do not use your voice when using the skill (such as using Bluff to <Link to="/rule/feint">feint</Link> in combat).</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-voice_of_the_sibyl--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Voice of the Sibyl</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 77</Link><br/>You overpower weaker and more vulnerable minds with your voice alone.<br/><strong>Prerequisites:</strong> Voice of the Sibyl.<br/><strong>Benefit:</strong> You gain a +1 bonus on all Bluff, Diplomacy, and Perform (oratory) skill checks for every 3 tiers you possess. This bonus stacks with the bonus from Voice of the Sibyl. If you have 10 or more ranks in at least two of these skills, gain a +2 bonus to the DC of any language-dependent spell you cast.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _volley_fire = {title: "Volley Fire", jsx: <><h2 id="feat-volley_fire-volley-fire-combat-teamwork">Volley Fire (Combat, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 10</Link></p>
<p>You have trained to work in ranks of archers to rain arrows down upon your foes.<br/><strong>Prerequisites:</strong> <Link to="/feat/point_blank_shot">Point-Blank Shot</Link>.<br/><strong>Benefit:</strong> You gain a +1 bonus on ranged attack rolls for each ally with this feat who made a ranged attack since the end of your last turn against a target within 15 feet of your target, to a maximum of +4. These allies don't provide cover against your attacks.</p>
</>};
const _voracious_blade = {title: "Voracious Blade", jsx: <><h2 id="feat-voracious_blade-voracious-blade-combat">Voracious Blade (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex pg. 59</Link></p>
<p>You can channel your daemonic energies through the vile blade you wield.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_focus">Weapon Focus</Link> (rhoka sword), base attack bonus +4, <Link to="/monster/urdefhan">urdefhan</Link>.<br/><strong>Benefit:</strong> When wielding a <Link to="/eq-weapon/rhoka_sword">rhoka sword</Link>, you can channel your daemonic energies through the blade as a swift action, causing it to deal Strength damage as your bite attack. You can use this ability a number of times per day equal to your Constitution modifier (minimum 1).</p>
</>};
const _vulpine_pounce = {title: "Vulpine Pounce", jsx: <><h2 id="feat-vulpine_pounce-vulpine-pounce-combat">Vulpine Pounce (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer pg. 5</Link></p>
<p>You can change shape mid-charge and pounce on an opponent in the same round.<br/><strong>Prerequisites:</strong> <Link to="/feat/swift_kitsune_shapechanger">Swift Kitsune Shapechanger</Link>, base attack bonus +10, <Link to="/race/kitsune">kitsune</Link>.<br/><strong>Benefit:</strong> When you change shape into your kitsune form and use the charge action in the same round, you can make a full attack against your opponent.</p>
</>};
const _waking_dream = {title: "Waking Dream", jsx: <><h2 id="feat-waking_dream-waking-dream">Waking Dream</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 30</Link></p>
<p>You can manipulate the world of dreams, even in your physical form.<br/><strong>Prerequisites:</strong> Cha 17, <Link to="/feat/ephemeral_tread">Ephemeral Tread</Link>, <Link to="/feat/lucid_dreamer">Lucid Dreamer</Link>, Knowledge (planes) 10 ranks.<br/><strong>Benefit:</strong> When in the <Link to="/rule/dimension_of_dreams">Dimension of Dreams</Link> in your physical body, you gain an additional attempt at an impossible action per day, for a total of two attempts. However, as a result of your meddling with the fabric of the realm, when you travel to the Dimension of Dreams in your physical body, you must succeed at a DC 15 Charisma check or arrive at a disadvantage.</p>
</>};
const _walking_sleight = {title: "Walking Sleight", jsx: <><h2 id="feat-walking_sleight-walking-sleight">Walking Sleight</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 95</Link></p>
<p>You've developed your skills at picking up items while on the move.<br/><strong>Prerequisites:</strong> <Link to="/feat/deft_hands">Deft Hands</Link>, Sleight of Hand 5 ranks.<br/><strong>Benefit:</strong> You no longer take the -20 penalty for attempting a <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> check as a move action. You can attempt a Sleight of Hand check as a standard action in the middle of your move action.<br/><strong>Normal:</strong> You can attempt a Sleight of Hand check as a move action only by taking a -20 penalty on the check.</p>
</>};
const _wall_of_flesh = {title: "Wall of Flesh", jsx: <><h2 id="feat-wall_of_flesh-wall-of-flesh-teamwork">Wall of Flesh (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion pg. 25</Link></p>
<p>You swarm with your allies, becoming a wall of creatures.<br/><strong>Prerequisites:</strong> Small size or smaller.<br/><strong>Benefit:</strong> When adjacent to an ally with this feat, you're considered one size category larger for determining CMD and the way <Link to="/rule/combat_maneuvers">combat maneuvers</Link> and abilities affect you.</p>
</>};
const _wand_dancer = {title: "Wand Dancer", jsx: <><h2 id="feat-wand_dancer-wand-dancer">Wand Dancer</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 289</Link>, <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 219</Link></p>
<p>You are trained in a tradition of Garundi courtesans and court mages that melds dance with the use of magic wands.<br/><strong>Prerequisites:</strong> Dex 13, <Link to="/feat/dodge">Dodge</Link>, <Link to="/feat/mobility">Mobility</Link>, Perform (dance) 5 ranks.<br/><strong>Benefit:</strong> When using a <Link to="/misc/spell_trigger">spell trigger</Link> item, you can move both before and after triggering the item, as long as the total distance moved is not greater than your speed. Choose one creature potentially affected by your spell trigger item. Your movement does not provoke attacks of opportunity from that creature only. You must move at least 5 feet before and after using your spell trigger item to utilize this feat.</p>
</>};
const _wanderers_fortune = {title: "Wanderer's Fortune", jsx: <><h2 id="feat-wanderers_fortune-wanderers-fortune-conduit">Wanderer's Fortune (Conduit)</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 33</Link></p>
<p>The promise of Elysium's freedom liberates you from all forms of restraint, allowing you to move as you will and to avoid numerous kinds of restraints that would otherwise vex a traveler or explorer.<br/><strong>Prerequisites:</strong> Knowledge (planes) 3 ranks.<br/><strong>Benefit:</strong> As a swift action, you gain the benefits of <Link to="/spell/freedom_of_movement">freedom of movement</Link> until the end of your turn or until you benefit from the effects to escape a <Link to="/rule/grapple">grapple</Link> or magical restraint, whichever comes first.</p>
<p>You can use this feat's benefit once per day, plus an additional time per day for every 5 ranks you have in Knowledge (planes).</p>
</>};
const _wandering_mind = {title: "Wandering Mind", jsx: <><h2 id="feat-wandering_mind-wandering-mind">Wandering Mind</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 13</Link></p>
<p>Your mind drifts swiftly from one thing to the next and is all but impossible to pin down.<br/><strong>Prerequisites:</strong> Character level 9th, <Link to="/race/gathlain">gathlain</Link>.<br/><strong>Benefit:</strong> When you fail a Will save against a mind-affecting effect that lasts more than 1 round, you can attempt another Will save on the round after your failed save. If you succeed, you gain the normal benefits of succeeding at a Will save against the effect. This feat offers only one additional saving throw against each effect.</p>
</>};
const _war_blessing = {title: "War Blessing", jsx: <><h2 id="feat-war_blessing-war-blessing">War Blessing</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 159</Link></p>
<p>Your fervent call to your deity imbues you with a temporary blessing.<br/><strong>Prerequisites:</strong> Mystery or domain class feature.<br/><strong>Benefit:</strong> Choose two warpriest <Link to="/ability/blessings">blessings</Link> when you take this feat. Each of these blessings must be tied to a domain granted by your deity or to one of the two domains that represent your spiritual inclination and abilities. Twice per day, you can call upon the minor blessing from one or the other of your chosen blessings. This ability otherwise acts like the warpriest blessings class feature. Your effective warpriest level is the highest level that you have in the class that has the mystery or domain class feature.</p>
</>};
const _war_singer = {title: "War Singer", jsx: <><h2 id="feat-war_singer-war-singer">War Singer</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 173</Link></p>
<p>Your songs draw upon the savage chants and brutal ways of your people, inspiring those around you to new heights of violence and savagery.<br/><strong>Prerequisites:</strong> Cha 13, <Link to="/ability/bardic_performance">bardic performance</Link> class feature, <Link to="/race/half_orc">half-orc</Link> or <Link to="/race/orc">orc</Link>.<br/><strong>Benefit:</strong> When you use bardic performance with audible components on a battlefield (any area where a combat involving a dozen or more combatants is taking place), the range or area of your chosen performance is doubled. In addition, the DC for saving throws against your bardic performance is increased by +2 for creatures of the orc subtype, regardless of where the performance occurs.</p>
</>};
const _warding_blood = {title: "Warding Blood", jsx: <><h2 id="feat-warding_blood-warding-blood">Warding Blood</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 6</Link></p>
<p>Your ethereal venom is strong enough to repel anyone who attempts to cross through it.<br/><strong>Prerequisites:</strong> <Link to="/feat/ghostbane_ichor">Ghostbane Ichor</Link>, Knowledge (religion) 13 ranks, <Link to="/race/vishkanya">vishkanya</Link>.<br/><strong>Benefit:</strong> You can spend 10 minutes and two uses of your vishkanya venom to coat an area no larger than 10 feet by 10 feet with your blood. This creates a <Link to="/spell/forbiddance">forbiddance</Link> effect, using your character level as your caster level (maximum 20). The save DC of this effect is equal to 15 + your Charisma modifier. Creatures that take damage from the <em>forbiddance</em> effect are also exposed to your vishkanya venom. If you have abilities that alter the effects of your venom, you must choose which effect applies when you create the venomous area.</p>
</>};
const _warleaders_rage = {title: "Warleader's Rage", jsx: <><h2 id="feat-warleaders_rage-warleaders-rage">Warleader's Rage</h2>
<p><strong>Sources</strong> <Link to="/source/orcs_of_golarion">Orcs of Golarion pg. 25</Link></p>
<p>Your rages are so inspiring to your allies that they don't have to remain adjacent to you to stay raging.<br/><strong>Prerequisites:</strong> Cha 13, <Link to="/race/half_orc">half-orc</Link> or <Link to="/race/orc">orc</Link>, non-lawful.<br/><strong>Benefit:</strong> Feats and abilities that allow an ally to rage or enhance a rage if adjacent to you (such as <Link to="/feat/amplified_rage">Amplified Rage</Link> and <Link to="/feat/sympathetic_rage">Sympathetic Rage</Link>) persist as long as your ally is within 30 feet of you and can see you. The conditions to activate the rage effect remain unchanged. For example, an ally with Sympathetic Rage must be adjacent to you to enter his own rage, but once his rage begins, he can continue raging as long as he can see you and you are within 30 feet.</p>
</>};
const _warmonger = {title: "Warmonger", jsx: <><h2 id="feat-warmonger-warmonger">Warmonger</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 117</Link></p>
<p>You are adept at instigating wars among those you advise or antagonize.<br/><strong>Prerequisites:</strong> Cha 13, <Link to="/race/hobgoblin">hobgoblin</Link>.<br/><strong>Benefit:</strong> You gain Bluff and Diplomacy as class skills. In addition, you receive a +4 competence bonus on Bluff and Diplomacy skill checks when using either skill to convince another character to go to war against or attack another creature or group.</p>
</>};
const _warning_shot = {title: "Warning Shot", jsx: <><h2 id="feat-warning_shot-warning-shot-combat">Warning Shot (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 11</Link></p>
<p>An intentional near-miss demonstrates your frightening skill at range.<br/><strong>Prerequisites:</strong> <Link to="/feat/point_blank_shot">Point-Blank Shot</Link>, <Link to="/feat/precise_shot">Precise Shot</Link>, <Link to="/feat/weapon_focus">Weapon Focus</Link>, proficiency with the selected weapon.<br/><strong>Benefit:</strong> As a standard action, you can make a ranged touch attack using a ranged weapon with which you have Weapon Focus. If successful, instead of dealing damage or applying any other effects of the attack, you may attempt an <Link to="/skill/intimidate">Intimidate</Link> check to demoralize the target as a free action. The target doesn't need to be within 30 feet, nor does it need to be able to see or hear you.</p>
</>};
const _warren_digger = {title: "Warren Digger", jsx: <><h2 id="feat-warren_digger-warren-digger">Warren Digger</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 81</Link>, <Link to="/source/classic_horrors_revisited">Classic Horrors Revisited pg. 32</Link></p>
<p>After years spent digging up graves, you are able to move through dirt almost as easily as a fish through water.<br/><strong>Prerequisites:</strong> <Link to="/monster/ghoul">Ghoul</Link>.<br/><strong>Benefit:</strong> You gain a burrow speed of 10 feet through earth, sand, or soil.<br/><strong>Special:</strong> You can gain this feat multiple times. Each time you take it, add 10 feet to your burrow speed, up to a maximum of your base land speed.</p>
</>};
const _warrior_priest = {title: "Warrior Priest", jsx: <><h2 id="feat-warrior_priest-warrior-priest">Warrior Priest</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 159</Link></p>
<p>Your religion is both a shield and a weapon in battle.<br/><strong>Prerequisites:</strong> Ability to cast divine spells, domain or mystery class feature.<br/><strong>Benefit:</strong> You gain a +1 bonus on initiative checks and a +2 bonus on <Link to="/rule/concentration">concentration</Link> checks made to cast a spell or use a spell-like ability when casting defensively or while grappled.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-warrior_priest--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Warrior Priest</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 77</Link><br/>Your faith speeds you in battle and further strengthens your mind and confidence.<br/><strong>Prerequisites:</strong> Warrior Priest.<br/><strong>Benefit:</strong> You gain a bonus equal to half your tier both on initiative checks and on concentration checks to cast a spell or use a spell-like ability when casting defensively or while grappled. These bonuses stack with the bonuses from Warrior Priest.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _wary_smuggler = {title: "Wary Smuggler", jsx: <><h2 id="feat-wary_smuggler-wary-smuggler">Wary Smuggler</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 7</Link></p>
<p>You are skilled at trading without the government's approval.<br/><strong>Prerequisites:</strong> Perception 5 ranks, Sleight of Hand 5 ranks, Stealth 5 ranks.<br/><strong>Benefit:</strong> You gain a +5 bonus on <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> checks to conceal small, non-weapon objects on your body, or on a single animal or vehicle with which you are traveling. While in urban areas, you can always take 10 on Perception checks, Sleight of Hand checks, and Stealth checks.</p>
</>};
const _wasp_familiar = {title: "Wasp Familiar", jsx: <><h2 id="feat-wasp_familiar-wasp-familiar">Wasp Familiar</h2>
<p><strong>Sources</strong> <Link to="/source/dirty_tactics_toolbox">Dirty Tactics Toolbox pg. 17</Link></p>
<p>The goddess of lust, revenge, and trickery has granted you a living sting to show her favor in you.<br/><strong>Prerequisites:</strong> Chaotic neutral alignment, worshiper of <Link to="/faith/calistria">Calistria</Link>.<br/><strong>Benefit:</strong> You gain a <Link to="/ability/familiar">familiar</Link> as per the arcane bond class feature, using your character level as your wizard level. The <Link to="/sidekick/familiar">familiar</Link> is a cat-sized, chaotic neutral wasp loyal to you. Use the statistics for a <Link to="/monster/greensting_scorpion">greensting scorpion</Link> familiar, but give it a base speed of 10 feet, a fly speed of 40 feet (average), no Climb bonus, and Fly +7. If you have the ability to gain a familiar through other means (such as the arcane bond class feature), and you are at least 5th level, instead use the statistics for an <Link to="/monster/imp">imp</Link>, but replace the <em>invisibility</em> spell-like ability with an <Link to="/spell/unnatural_lust">unnatural lust</Link> (DC 14) spell-like ability usable three times per day. You can have only one familiar.</p>
<p>If you ever grossly violate the code of conduct required by Calistria (a violation of the scale that would cause a cleric of Calistria to lose all spells and class features), your familiar turns on you and attacks you until it is killed. To regain a familiar, you must atone for your deeds with the <Link to="/spell/atonement">atonement</Link> spell, and pay to have the slain familiar raised from the dead. If your familiar is slain or lost through other means, you can replace it using the normal rules for replacing familiars.</p>
<p><strong>Special:</strong> This feat can be taken a second time by characters of 7th or higher level if they do not otherwise have access to familiars. Such characters have access to a wasp familiar that uses the statistics for an imp, as described above.</p>
</>};
const _water_skinned = {title: "Water Skinned", jsx: <><h2 id="feat-water_skinned-water-skinned">Water Skinned</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 178</Link></p>
<p>Your touch extinguishes small flames.<br/><strong>Prerequisites:</strong> <Link to="/race/undine">Undine</Link>.<br/><strong>Benefit:</strong> As a standard action, you can extinguish a small nonmagical fire with a touch, affecting anything up to the size of a large campfire. This ability does not affect fires with a total area greater than 5 square feet. Touching the fire in this way does not harm you.</p>
</>};
const _waterway_caster = {title: "Waterway Caster", jsx: <><h2 id="feat-waterway_caster-waterway-caster">Waterway Caster</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 119</Link>, <Link to="/source/people_of_the_river">People of the River pg. 25</Link></p>
<p>You've learned to cast spells while on a watercraft or even while swimming in turbulent waters.<br/><strong>Benefit:</strong> You automatically succeed at <Link to="/rule/concentration">concentration</Link> checks required to cast a spell while being subjected to vigorous or violent motion while either swimming or on a ship. You gain a +4 bonus on concentration checks to cast spells underwater.</p>
</>};
const _wave_master = {title: "Wave Master", jsx: <><h2 id="feat-wave_master-wave-master">Wave Master</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 217</Link></p>
<p>Gozreh has seen fit to bless you as an uncommonly skilled swimmer.<br/><strong>Prerequisites:</strong> Worshiper of <Link to="/faith/gozreh">Gozreh</Link>.<br/><strong>Benefit:</strong> When you succeed at a Swim check, you can move your full speed as a full-round action or half your speed as a move action. This does not grant you the benefit of having a swim speed.<br/><strong>Normal:</strong> A successful Swim check allows you to move up to half your speed as a full-round action or up to a quarter your speed as a move action.</p>
</>};
const _wave_strike = {title: "Wave Strike", jsx: <><h2 id="feat-wave_strike-wave-strike-combat">Wave Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 123</Link></p>
<p>You present a serene facade until you unsheathe your weapon and strike in one fluid motion.<br/><strong>Prerequisites:</strong> Weapon expertise class feature or <Link to="/feat/quick_draw">Quick Draw</Link>, Bluff 1 rank.<br/><strong>Benefit:</strong> If on your first turn of combat you draw a melee weapon to attack an opponent within your reach, you can spend a swift action to make a Bluff check to <Link to="/rule/feint">feint</Link> against that opponent.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-wave_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-wave_strike-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>You can spend 2 stamina points to use this feat on your second or subsequent turns in a combat. You can use this combat trick only once per combat, though you can use it in addition to using the feat on your first turn.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _wayang_soothsayer = {title: "Wayang Soothsayer", jsx: <><h2 id="feat-wayang_soothsayer-wayang-soothsayer">Wayang Soothsayer</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 11</Link></p>
<p>You embody the ideals of wayang society and culture.<br/><strong>Prerequisites:</strong> <Link to="/race/wayang">Wayang</Link>.<br/><strong>Benefit:</strong> You gain the shadow speaker racial trait. If you already have the shadow speaker racial trait, you can increase the number of times per day that you can use shadow speaker by 1, and increase the insight bonus granted from each type of use by 1.<br/><strong>Special:</strong> This feat can be taken once at 1st level, and again at 11th level.</p>
</>};
const _we_are_the_wall = {title: "We are the Wall", jsx: <><h2 id="feat-we_are_the_wall-we-are-the-wall-story">We are the Wall (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_131_the_reapers_right_hand">Pathfinder #131: The Reaper's Right Hand pg. 76</Link></p>
<p>You embody your family's legendary monster-hunters.<br/><strong>Prerequisites:</strong> Be a member of House Darahan, or have the <Link to="/rule/class_background_tables">Champion of the People (cavalier) or Duty (fighter)</Link> background, or the <Link to="/rule/birth_circumstances_and_more">Raiders</Link> major childhood event background.<br/><strong>Benefit:</strong> Three times per day as a move action, you can declare a single dragon, magical beast, or monstrous humanoid within 50 feet and in line of sight to be your mark. You gain a +1 bonus on attack rolls and on Bluff, Knowledge, Perception, Sense Motive, and Survival checks against your mark. These bonuses last for 1 minute, until you designate a new mark, or until the mark is dead. After you have declared a creature as your mark, it can't be your mark again for another 24 hours.<br/><strong>Goal:</strong> Protect a settlement you have lived in for at least a year from an invading force consisting of an appropriate number of dragons, magical beasts, or monstrous humanoids.<br/><strong>Completion Benefit:</strong> The bonus provided by your mark becomes +1 for every 4 character levels you have, to a maximum of +5.</p>
</>};
const _weapon_adept = {title: "Weapon Adept", jsx: <><h2 id="feat-weapon_adept-weapon-adept-combat">Weapon Adept (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 11</Link></p>
<p>You are skilled at using customized weaponry.<br/><strong>Benefit:</strong> Choose a <Link to="/main/equipment_weaponenhancements">weapon modification</Link> (such as <Link to="/eq-weaponenh/jagged_hooks">jagged hooks</Link>). You treat weapons with that modification as being of their normal category (simple, martial, or exotic).<br/><strong>Normal:</strong> A modified weapon is treated as one category more difficult to wield.<br/><strong>Special:</strong> You can gain this feat multiple times, choosing a different weapon modification each time.</p>
</>};
const _weapon_bearer = {title: "Weapon Bearer", jsx: <><h2 id="feat-weapon_bearer-weapon-bearer">Weapon Bearer</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 135</Link></p>
<p>You attract a weapon bearer to aid you in your endeavors.<br/><strong>Prerequisites:</strong> Character level 4th, proficient with all martial weapons.<br/><strong>Benefit:</strong> This feat is similar to the <Link to="/feat/leadership">Leadership</Link> feat, with several exceptions. You can attract only a 1st-level cohort (referred to hereafter as a weapon bearer) with this feat, and can't recruit followers. You determine your Leadership score according to the rules presented in the Leadership feat, but your weapon bearer is always at least 3 levels lower than yourself.</p>
<p>A weapon bearer can take levels in only cavalier, fighter, or gunslinger. She cannot multiclass, though she can take any archetype for which she qualifies.</p>
<p>Once per round as a move action that does not provoke attacks of opportunity, you can retrieve an item carried by your weapon bearer. In addition, your weapon bearer can pick up items you drop as an immediate action. In order to use either of these abilities, you and your weapon bearer must be adjacent to each other and must both be able to move and communicate with each other.</p>
<p>If a weapon bearer gains enough XP to bring her to 2 levels lower than your level, she doesn't gain the new level until you gain your next level; until you advance, her XP total remains 1 less than the amount needed to attain the next level.</p>
<p>If you release your weapon bearer from service or otherwise lose your weapon bearer, you can recruit a new one. At 7th level, you can swap this feat for the Leadership feat.</p>
</>};
const _weapon_evoker_mastery = {title: "Weapon Evoker Mastery", jsx: <><h2 id="feat-weapon_evoker_mastery-weapon-evoker-mastery-item-mastery">Weapon Evoker Mastery (Item Mastery)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 31</Link></p>
<p>You rack opponents with eldritch power coursing from your magic weapons.<br/><strong>Prerequisites:</strong> Use Magic Device 2 ranks, base Fortitude saving throw bonus +3.<br/><strong>Benefit:</strong> As a swift action while wielding a magic weapon with a weapon special ability that deals extra acid, cold, fire, electricity, or sonic damage on a hit, you deal an additional 1d4 points of damage of the same type with each hit you make with that weapon for 1 round.</p>
</>};
const _weapon_finesse = {title: "Weapon Finesse", jsx: <><h2 id="feat-weapon_finesse-weapon-finesse-combat">Weapon Finesse (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 136</Link></p>
<p>You are trained in using your agility in melee combat, as opposed to brute strength.<br/><strong>Benefit:</strong> With a light weapon, <Link to="/eq-weapon/rapier">rapier</Link>, <Link to="/eq-weapon/whip">whip</Link>, or <Link to="/eq-weapon/spiked_chain">spiked chain</Link> made for a creature of your size category, you may use your Dexterity modifier instead of your Strength modifier on attack rolls. If you carry a shield, its armor check penalty applies to your attack rolls.<br/><strong>Special:</strong> Natural weapons are considered light weapons.</p>
<p><strong>Extra:</strong> Further publications expanded the number of weapons that can be used with Weapon Finesse. Sometimes there are restrictions on this behavior: check the weapon entry to be sure.</p>
<ul>
<li><Link to="/eq-weapon/aldori_dueling_sword">Aldori dueling sword</Link></li>
<li><Link to="/eq-weapon/bladed_scarf">Bladed scarf</Link></li>
<li><Link to="/eq-weapon/elven_branched_spear">Elven branched spear</Link></li>
<li><Link to="/eq-weapon/elven_curve_blade">Elven curve blade</Link></li>
<li><Link to="/eq-weapon/elven_thornblade">Elven thornblade</Link></li>
<li><Link to="/eq-weapon/estoc">Estoc</Link></li>
<li><Link to="/eq-weapon/spiral_rapier">Spiral rapier</Link></li>
<li><Link to="/eq-weapon/sword_cane">Sword cane</Link></li>
</ul>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-weapon_finesse--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-weapon_finesse-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>You can spend 2 stamina points to negate the penalty on attack rolls from your shield's armor check penalty until the start of your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-weapon_finesse--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Weapon Finesse</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 77</Link><br/>You're an expert with weapons that rely on your agility.<br/><strong>Prerequisites:</strong> Weapon Finesse.<br/><strong>Benefit:</strong> When using Weapon Finesse, you may also use your Dexterity modifier instead of your Strength modifier on your damage rolls. If you carry a shield, its armor check penalty doesn't apply to either the attack rolls or the damage rolls.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-weapon_finesse--table-2"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>The Weapon Finesse feat has been removed, and now any character may choose to use their dexterity bonus to hit with light melee weapons. As a consequence, the Light Melee Weapons designation has been renamed to <Link to="/rule/finesse">Finesse</Link> Melee Weapons. A new special weapon feature called <Link to="/rule/equipment_errata">agile</Link> has been added for melee weapons that are one-handed or two-handed but can still be finessed, such as the <Link to="/eq-weapon/rapier">rapier</Link>.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _weapon_focus = {title: "Weapon Focus", jsx: <><h2 id="feat-weapon_focus-weapon-focus-combat">Weapon Focus (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 136</Link></p>
<p>Choose one type of weapon. You can also choose unarmed strike or grapple (or ray, if you are a spellcaster) as your weapon for the purposes of this feat.<br/><strong>Prerequisites:</strong> Proficiency with selected weapon, base attack bonus +1.<br/><strong>Benefit:</strong> You gain a +1 bonus on all attack rolls you make using the selected weapon.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take the feat, it applies to a new type of weapon.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-weapon_focus--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-weapon_focus-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>Once per round, you can spend 2 stamina points to gain your Weapon Focus bonus on attack rolls with a weapon with which you don't have Weapon Focus. This bonus lasts until the start of your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-weapon_focus--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Weapon Focus</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 77</Link><br/>You're a master of one type of weapon.<br/><strong>Prerequisites:</strong> Weapon Focus.<br/><strong>Benefit:</strong> Double the bonuses on your attack rolls from Weapon Focus and <Link to="/feat/greater_weapon_focus">Greater Weapon Focus</Link>. As a swift action, you can expend one use of mythic power to gain a bonus on attack rolls with your selected weapon equal to half your tier until the end of your turn.<br/><strong>Special:</strong> If you have taken non-mythic Weapon Focus multiple times, you must choose which of those feats this enhances. You can take this feat multiple times. The effects do not stack. Each time you take this feat, it applies to a different non-mythic Weapon Focus feat you have.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-weapon_focus--table-2"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>Choose one <Link to="/ability/weapon_groups">weapon group</Link> listed under the fighter's Weapon Training class feature.
<strong>Prerequisites:</strong> Proficiency with at least one weapon from the selected weapon group, base attack bonus +1.<br/><strong>Benefit:</strong> You gain a +1 bonus on all attack rolls you make using any weapon from the selected group.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take the feat, it applies to a new weapon group.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _weapon_material_mastery = {title: "Weapon Material Mastery", jsx: <><h2 id="feat-weapon_material_mastery-weapon-material-mastery-weapon-mastery">Weapon Material Mastery (Weapon Mastery)</h2>
<p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 23</Link></p>
<p>You can perform impressive deeds with weapons made from peculiar materials.<br/><strong>Prerequisites:</strong> Base attack bonus +7, weapon training class feature with a melee weapon.<br/><strong>Benefit:</strong> While wielding an appropriate melee weapon, you gain the following special abilities, based on which special material the weapon is primarily constructed of (if any).</p>
<p><strong className="hl">Adamantine:</strong> Your critical hits ignore the target's DR.</p>
<p><strong className="hl">Alchemical Silver, Mithral, or Silversheen:</strong> When you successfully deal damage to a creature that is under the effects of an illusion or polymorph effect (such as <Link to="/spell/disguise_self">disguise self</Link> or the <Link to="/umr/change_shape">change shape</Link> special ability), its wound fizzles and boils loudly, revealing the presence of such effects. If the effect is a racial ability, anyone that sees you attack the creature gains a +4 bonus on Knowledge checks to identify the creature. In addition, you immediately receive a Will save to disbelieve any illusion effect on the creature that allows disbelief.</p>
<p><strong className="hl">Cold Iron:</strong> When you score a critical hit against a target benefiting from spells that grant temporary hit points or bonuses to AC, ability scores, attack rolls, damage rolls, or saving throws, you must immediately attempt a special dispel check (1d20 + your base attack bonus) as a targeted dispel as per the <Link to="/spell/dispel_magic">dispel magic</Link> spell, but targeting only those spells. Once a creature has been the target of this effect, you can't affect it in this way again for 24 hours.</p>
<p><strong className="hl">Elysium Bronze:</strong> When you damage a magical beast or monstrous humanoid, the creature must succeed at a Fortitude save (DC = 10 + 1/2 your base attack bonus + your Strength modifier) or lose access to a randomly selected supernatural or spell-like ability (if any). Once a creature has been the target of this effect, you can't affect it in this way again for 24 hours.</p>
<p><strong className="hl">Fire-Forged Steel or Frost-Forged Steel:</strong> When your weapon is exposed to 10 points or more of energy damage (fire for fire-forged steel or cold for frost-forged steel), the weapon adds +1d6 points of energy damage to its attacks instead of +1d4 points of energy damage. Additionally, the duration of this effect increases by 1 round for every 5 points of the appropriate type of energy damage to which the weapon is exposed beyond 10.</p>
<p><strong className="hl">Greenwood or Living Steel:</strong> When you score a critical hit, the target must succeed at a Fortitude save (DC = 10 + 1/2 your base attack bonus + your Strength modifier) or lose its <Link to="/umr/fast_healing">fast healing</Link> and <Link to="/umr/regeneration">regeneration</Link> (if any) for 1d3 rounds.</p>
<p><strong className="hl">Viridium:</strong> You add your Strength modifier and the weapon's enhancement bonus (if any) to the Fortitude DC to determine if a foe struck by the weapon contracts <Link to="/disease/leprosy">leprosy</Link>.</p>
<p><strong className="hl">Whipwood:</strong> The weapon gains the <Link to="/misc/trip">trip</Link> special weapon feature, and you gain a +2 bonus on <Link to="/rule/trip">trip</Link> combat maneuvers made with it.</p>
<p><strong className="hl">Wyroot:</strong> Once per turn, you can absorb life points from the weapon as a free action instead of a swift action. You can never absorb life points from wyroot weapons or equipment more than once per turn.</p>
</>};
const _weapon_of_the_chosen = {title: "Weapon of the Chosen", jsx: <><h2 id="feat-weapon_of_the_chosen-weapon-of-the-chosen-combat">Weapon of the Chosen (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 159</Link></p>
<p>The influence of your deity guides your favored weapon.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_focus">Weapon Focus</Link> with deity's favored weapon, must worship and receive spells from a deity.<br/><strong>Benefit:</strong> As a swift action, you can call upon your deity to guide an attack you make with your deity's favored weapon. On your next attack in that round with that weapon, your weapon counts as magical for the purpose of overcoming damage reduction or striking an incorporeal creature. If your attack misses because of <Link to="/rule/concealment">concealment</Link>, you can reroll your miss chance one time to see whether you actually hit.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-weapon_of_the_chosen--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-weapon_of_the_chosen-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>When using this feat, you can spend 5 stamina points to designate a weapon other than your deity's favored weapon. You gain this feat's benefits with that weapon until the start of your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _weapon_shift = {title: "Weapon Shift", jsx: <><h2 id="feat-weapon_shift-weapon-shift">Weapon Shift</h2>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins pg. 9</Link></p>
<p>Your melee weapons meld into your animal form.<br/><strong>Prerequisites:</strong> Wild shape class feature.<br/><strong>Benefit:</strong> When you use your wild shape ability, any melee weapons you are wielding and proficient with meld into your new form. Select one of these weapons; while in your new form, your natural attacks deal the same damage type as that weapon. Your natural attacks also gain all of the weapon's properties (such as <Link to="/misc/disarm">disarm</Link>), other than the <Link to="/misc/double">double</Link> weapon property and the <Link to="/misc/fragile">fragile</Link> weapon property; moreover, when using this feat to grant the <Link to="/misc/trip">trip</Link> property to your natural attacks, you gain a +2 bonus on combat maneuver checks to trip an enemy, but you cannot drop your weapon to avoid being tripped due to a failed trip attempt. Weapon Shift does not apply a magic weapon's enhancement bonus to your natural attacks, nor does it grant your natural attacks any of a weapon's magical special abilities.</p>
</>};
const _weapon_specialization = {title: "Weapon Specialization", jsx: <><h2 id="feat-weapon_specialization-weapon-specialization-combat">Weapon Specialization (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 137</Link></p>
<p>You are skilled at dealing damage with one weapon. Choose one type of weapon (including unarmed strike or grapple) for which you have already selected the Weapon Focus feat. You deal extra damage when using this weapon.<br/><strong>Prerequisites:</strong> Proficiency with selected weapon, <Link to="/feat/weapon_focus">Weapon Focus</Link> with selected weapon, fighter level 4th.<br/><strong>Benefit:</strong> You gain a +2 bonus on all damage rolls you make using the selected weapon.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take the feat, it applies to a new type of weapon.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-weapon_specialization--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-weapon_specialization-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>Once per round, you can spend 2 stamina points to gain your Weapon Specialization bonus on damage rolls with a weapon with which you don't have Weapon Specialization. This bonus lasts until the start of your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-weapon_specialization--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Weapon Specialization</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 77</Link><br/>The damage you deal with your chosen weapon is truly awesome to behold.<br/><strong>Prerequisites:</strong> Weapon Specialization.<br/><strong>Benefit:</strong> When using your chosen weapon, you gain a bonus equal to half your tier on damage rolls. This stacks with the bonus from Weapon Specialization and <Link to="/feat/greater_weapon_specialization">Greater Weapon Specialization</Link>.<br/><strong>Special:</strong> If you have taken non-mythic Weapon Specialization multiple times, you must choose which of those feats this enhances. You can take this feat multiple times. The effects do not stack. Each time you take this feat, it applies to a different non-mythic Weapon Specialization feat you have.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-weapon_specialization--table-2"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>You are skilled at dealing damage with one type of weapon. Choose one <Link to="/ability/weapon_groups">weapon group</Link> listed under the fighter's Weapon Training class feature for which you have already selected the Weapon Focus feat. You deal extra damage when using these weapons.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_focus">Weapon Focus</Link> with selected weapon group, fighter level 4th.<br/><strong>Benefit:</strong> You gain a +2 bonus on all damage rolls you make using the selected weapon.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take the feat, it applies to a new weapon group.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _weapon_style_mastery = {title: "Weapon Style Mastery", jsx: <><h2 id="feat-weapon_style_mastery-weapon-style-mastery-style-weapon-mastery">Weapon Style Mastery (Style, Weapon Mastery)</h2>
<p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 23</Link></p>
<p>You can combine multiple fighting styles together.<br/><strong>Prerequisites:</strong> Any two <Link to="/main/style_feat">style feats</Link> from different styles, base attack bonus +6, weapon training class feature with a melee weapon.<br/><strong>Benefit:</strong> Choose one weapon style (a style feat that lists <Link to="/feat/weapon_focus">Weapon Focus</Link> as a prerequisite) that you have. You can have the chosen style and a second style active at once. Starting a stance provided by a style feat is still a swift action, but you can assume both the chosen weapon style's stance and another style's stance simultaneously using this action. This ability doesn't stack with other abilities that allow you to have multiple styles active at the same time.<br/><strong>Normal:</strong> You can have only one style active at once.</p>
</>};
const _weapon_trick = {title: "Weapon Trick", notBookmarkable: true, jsx: <><h2 id="feat-weapon_trick-weapon-trick-combat">Weapon Trick (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 12</Link>, <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 8-9</Link></p>
<p>Choose one weapon trick option (one-handed weapon, polearm, ranged, two-handed weapon, two-weapon, or weapon and shield). You can perform weapon tricks in combat when armed appropriately for that option.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> You can use any weapon tricks relating to the chosen weapon option if you meet the trick's prerequisites and are proficient with any weapon or shield that you use as part of the trick.<br/><strong>Special:</strong> You can gain Weapon Trick multiple times. Each time you take the feat, it applies to a new weapon trick option. (These are listed as separate feats for reading convenience.)</p>
<ul>
<li><Link to="/feat/weapon_trick_one_handed_weapon">Weapon Trick (One-Handed Weapon)</Link></li>
<li><Link to="/feat/weapon_trick_polearm">Weapon Trick (Polearm)</Link></li>
<li><Link to="/feat/weapon_trick_ranged_weapon">Weapon Trick (Ranged Weapon)</Link></li>
<li><Link to="/feat/weapon_trick_two_handed_weapon">Weapon Trick (Two-Handed Weapon)</Link></li>
<li><Link to="/feat/weapon_trick_two_weapon">Weapon Trick (Two-Weapon)</Link></li>
<li><Link to="/feat/weapon_trick_weapon_and_shield">Weapon Trick (Weapon and Shield)</Link></li>
</ul>
</>};
const _weapon_trick_one_handed_weapon = {hasJL:true,title: "Weapon Trick (One-Handed Weapon)", jsx: <><div className="jumpList" id="feat-weapon_trick_one_handed_weapon-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="feat-weapon_trick_one_handed_weapon-one-handed-weapon-tricks">One-Handed Weapon Tricks</InnerLink></li></ul></div><h2 id="feat-weapon_trick_one_handed_weapon-weapon-trick-one-handed-weapon-combat">Weapon Trick (One-Handed Weapon) (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 12</Link>, <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 8-9</Link></p>
<p>Choose one weapon trick option (one-handed weapon, polearm, ranged, two-handed weapon, two-weapon, or weapon and shield). You can perform weapon tricks in combat when armed appropriately for that option.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> You can use any weapon tricks relating to the chosen weapon option if you meet the trick's prerequisites and are proficient with any weapon or shield that you use as part of the trick.<br/><strong>Special:</strong> You can gain <Link to="/feat/weapon_trick">Weapon Trick</Link> multiple times. Each time you take the feat, it applies to a new weapon trick option. (These are listed as separate feats for reading convenience.)</p>
<h3 id="feat-weapon_trick_one_handed_weapon-one-handed-weapon-tricks" data-hash-target>One-Handed Weapon Tricks</h3>
<p>These weapon tricks are common among the Aldori swordlords and many weapon masters of Tian Xia. You can use these tricks only while wearing light or no armor, wielding a light or one-handed manufactured weapon in one hand, and holding nothing in your off hand.</p>
<p><strong className="hl">Free Hand Maneuver</strong> (base attack bonus +6): As a full-round action, you can make a single attack with your weapon and attempt to perform a <Link to="/rule/dirty_trick">dirty trick</Link>, <Link to="/rule/disarm">disarm</Link>, <Link to="/rule/drag">drag</Link>, <Link to="/rule/reposition">reposition</Link>, or <Link to="/rule/steal">steal</Link> combat maneuver with your free hand, taking no penalties for <Link to="/rule/two_weapon_fighting">two-weapon fighting</Link>. The combat maneuver provokes attacks of opportunities as normal, unless you have an appropriate ability or feat. You are not considered unarmed for this maneuver, but can't apply any benefits of your weapon to the combat maneuver check.</p>
<p><strong className="hl">Mindful Dodge</strong> (<Link to="/feat/dodge">Dodge</Link>): As an immediate action, you can gain a +4 dodge bonus to your AC against a single of which attack you are aware. You must make this decision before the attack roll is revealed. You are staggered on your next turn.</p>
<p><strong className="hl">Strike and Seize</strong> (<Link to="/feat/improved_disarm">Improved Disarm</Link>, base attack bonus +6): As a standard action, you can make a single attack with your weapon and attempt to perform a disarm combat maneuver with your free hand, taking no penalties for two-weapon fighting.</p>
<p><strong className="hl">Stylish Riposte</strong> (<Link to="/feat/combat_reflexes">Combat Reflexes</Link>, base attack bonus +4): When your AC exceeds the result of a foe's melee attack against you by 5 or more, that foe provokes an attack of opportunity from you. Once you make such an attack of opportunity against a foe, you can't again use this trick against the foe that day.</p>
<p><strong className="hl">Grab and Stab</strong> (<Link to="/feat/improved_grapple">Improved Grapple</Link>, base attack bonus +6): As a standard action, you can initiate a <Link to="/rule/grapple">grapple</Link> with your free hand (taking the usual -4 penalty for not having two hands free). If the attempt is successful, you can immediately follow up with an attack using your light or one-handed weapon as a free action. If you do so, you can't use any other abilities that are triggered by a successful grapple combat maneuver check (such as <Link to="/umr/constrict">constrict</Link>). The grapple attempt provokes attacks of opportunity as normal unless you have an ability or feat that prevents this.</p>
<p><strong className="hl">Switch Hands</strong> (<Link to="/feat/improved_feint">Improved Feint</Link>): As a free action, you can pass a light or one-handed weapon you are wielding to your free hand. If you attempt a <Link to="/rule/feint">feint</Link> during the same round, you gain a +2 bonus on your Bluff check. Once you have used this weapon trick against a target, you can't gain the bonus against the same creature until 24 hours have passed.</p>
</>};
const _weapon_trick_polearm = {title: "Weapon Trick (Polearm)", jsx: <><h2 id="feat-weapon_trick_polearm-weapon-trick-polearm-combat">Weapon Trick (Polearm) (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 12</Link>, <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 8-9</Link></p>
<p>Choose one weapon trick option (one-handed weapon, polearm, ranged, two-handed weapon, two-weapon, or weapon and shield). You can perform weapon tricks in combat when armed appropriately for that option.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> You can use any weapon tricks relating to the chosen weapon option if you meet the trick's prerequisites and are proficient with any weapon or shield that you use as part of the trick.<br/><strong>Special:</strong> You can gain <Link to="/feat/weapon_trick">Weapon Trick</Link> multiple times. Each time you take the feat, it applies to a new weapon trick option. (These are listed as separate feats for reading convenience.)</p>
<p>These weapon tricks are common in southern Garund and parts of Iobaria and Arcadia. You can use these tricks only while wielding a weapon from the polearm <Link to="/ability/weapon_groups">weapon group</Link>.</p>
<p><strong className="hl">Choke Up</strong> (Acrobatics 1 rank, Climb 1 rank): You can take a -2 penalty on attack rolls and damage rolls until the beginning of your next turn in order to choke up on and wield a two-handed polearm sized for you in one hand, as long as you do not make attacks with your other hand.</p>
<p><strong className="hl">Close Sweep</strong> (<Link to="/feat/improved_bull_rush">Improved Bull Rush</Link>, <Link to="/feat/improved_reposition">Improved Reposition</Link>, or <Link to="/feat/improved_trip">Improved Trip</Link>): You can attempt a <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/reposition">reposition</Link>, or <Link to="/rule/trip">trip</Link> combat maneuver check (one for which you have the matching prerequisite feat) against an adjacent foe, even if wielding a weapon with the <Link to="/misc/reach">reach</Link> quality.</p>
<p><strong className="hl">Haft Bash</strong> (<Link to="/feat/weapon_focus">Weapon Focus</Link>): You can accept a -2 penalty on attack rolls with a reach polearm for which you have Weapon Focus in order to treat the weapon as if it lacked the reach quality until the start of your next turn. If you do, the polearm functions as a <Link to="/eq-weapon/club">club</Link>. Any qualities (such as <Link to="/misc/trip">trip</Link>) or special abilities (such as <Link to="/magic-enh/keen">keen</Link>) of the weapon that a club could not have, and any feats or abilities you can't apply to a club, don't apply to attacks with the weapon during this time.</p>
<p><strong className="hl">Polearm Balance</strong> (Acrobatics 10 ranks): You can use a polearm to improve your balance. Any round in which you do not make a melee attack, you can take 10 on an Acrobatics check even when distraction would normally prevent you from doing so.</p>
<p><strong className="hl">Quick Brace</strong> (base attack bonus +6): While taking a full-attack action with a polearm with <Link to="/misc/brace">brace</Link>, you can <Link to="/rule/ready">ready</Link> an attack with the polearm in place of your final attack. The readied attack uses the attack bonus of the attack you used to ready it.</p>
<p><strong className="hl">Pole Vault</strong> (Acrobatics 3 ranks): You gain a +4 bonus on Acrobatics checks to jump, and you count as having a running start if you move at least 5 feet before jumping.</p>
</>};
const _weapon_trick_ranged_weapon = {title: "Weapon Trick (Ranged Weapon)", jsx: <><h2 id="feat-weapon_trick_ranged_weapon-weapon-trick-ranged-weapon-combat">Weapon Trick (Ranged Weapon) (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 12</Link>, <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 8-9</Link></p>
<p>Choose one weapon trick option (one-handed weapon, polearm, ranged, two-handed weapon, two-weapon, or weapon and shield). You can perform weapon tricks in combat when armed appropriately for that option.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> You can use any weapon tricks relating to the chosen weapon option if you meet the trick's prerequisites and are proficient with any weapon or shield that you use as part of the trick.<br/><strong>Special:</strong> You can gain <Link to="/feat/weapon_trick">Weapon Trick</Link> multiple times. Each time you take the feat, it applies to a new weapon trick option. (These are listed as separate feats for reading convenience.)</p>
<p>These weapon tricks are common among the Chernasardo Rangers of Fangwood and the archers trained by House Narikopolus in Cheliax. You can use these tricks while wielding a ranged weapon</p>
<p><strong className="hl">Hindering Shot</strong> (<Link to="/feat/precise_shot">Precise Shot</Link>, <Link to="/feat/snap_shot">Snap Shot</Link>): You can distract a foe at a crucial moment, making it vulnerable to your allies' abilities. You can <Link to="/rule/ready_an_action">ready an action</Link> to make a ranged attack against a foe when an ally forces the foe to attempt a saving throw. If your attack hits the foe and deals damage, the foe takes a -4 penalty on the saving throw that triggered your readied action.</p>
<p><strong className="hl">Suppressing Shot</strong> (<Link to="/feat/far_shot">Far Shot</Link>, Precise Shot): You can cover an ally's momentary vulnerability. You can ready an action to make a ranged attack against a foe when it makes an attack of opportunity. If your attack hits and damages the foe, the foe's attack of opportunity automatically misses its target.</p>
</>};
const _weapon_trick_two_handed_weapon = {title: "Weapon Trick (Two-Handed Weapon)", jsx: <><h2 id="feat-weapon_trick_two_handed_weapon-weapon-trick-two-handed-weapon-combat">Weapon Trick (Two-Handed Weapon) (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 12</Link>, <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 8-9</Link></p>
<p>Choose one weapon trick option (one-handed weapon, polearm, ranged, two-handed weapon, two-weapon, or weapon and shield). You can perform weapon tricks in combat when armed appropriately for that option.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> You can use any weapon tricks relating to the chosen weapon option if you meet the trick's prerequisites and are proficient with any weapon or shield that you use as part of the trick.<br/><strong>Special:</strong> You can gain <Link to="/feat/weapon_trick">Weapon Trick</Link> multiple times. Each time you take the feat, it applies to a new weapon trick option. (These are listed as separate feats for reading convenience.)</p>
<p>These weapon tricks are known to dwarves of the Five Kings Mountains and Shoanti champions of the Cinderlands. You can use these tricks while wielding any two-handed weapon.</p>
<p><strong className="hl">Cleaving Smash</strong> (<Link to="/feat/cleave">Cleave</Link>, <Link to="/feat/improved_vital_strike">Improved Vital Strike</Link>, <Link to="/feat/power_attack">Power Attack</Link>): When you use Cleave, you can add the additional damage from <Link to="/feat/vital_strike">Vital Strike</Link> to both your initial and your secondary attacks. If you also have the <Link to="/feat/greater_vital_strike">Greater Vital Strike</Link> feat, you can instead add the damage from Improved Vital Strike to both your initial and your secondary attacks.</p>
<p><strong className="hl">Crush Armor</strong> (<Link to="/feat/improved_sunder">Improved Sunder</Link>, Power Attack): When you deal damage to a foe's armor with a successful <Link to="/rule/sunder">sunder</Link> combat maneuver check while using a two-handed weapon, the foe must succeed at a Fortitude save (DC = 10 + 1/2 your base attack bonus + your Strength modifier) or be <Link to="/misc/fatigued">fatigued</Link> for 1 round. If the armor has the <Link to="/misc/broken">broken</Link> condition after you damage it, the foe must continue making this save every round until he removes the armor or the armor loses the broken condition. If the armor is destroyed by your sunder attempt, the foe is automatically fatigued for 1 round. The foe cannot become <Link to="/misc/exhausted">exhausted</Link> this way.</p>
<p><strong className="hl">Two-Handed Menace</strong> (Intimidate 5 ranks): Capitalizing on the fear inspired by massive weapons, you can take 10 on <Link to="/skill/intimidate">Intimidate</Link> checks even when distracted or in combat.</p>
<p><strong className="hl">Warding Weapon</strong> (<Link to="/feat/combat_expertise">Combat Expertise</Link>): While you are using the <Link to="/misc/total_defense">total defense</Link> action, <Link to="/misc/fighting_defensively">fighting defensively</Link>, or using Combat Expertise, you gain a +1 shield bonus to AC.</p>
<p><strong className="hl">One-Handed Lunge</strong> (base attack bonus +6): As a standard action, you can release one of your hands holding a two-handed weapon and make a melee attack with the weapon, increasing your reach by 5 feet for the duration of the attack. If the attack hits, you deal damage as if using a one-handed weapon, adding only your Strength bonus to damage if you are using your primary hand or half your Strength bonus if you are using your off hand, instead of 1-1/2 times your Strength bonus. Otherwise, you take no penalty for using the weapon one-handed. The extra reach doesn't stack with the <Link to="/feat/lunge">Lunge</Link> feat or other effects that extend your melee reach beyond that granted by your size category.</p>
</>};
const _weapon_trick_two_weapon = {title: "Weapon Trick (Two-Weapon)", jsx: <><h2 id="feat-weapon_trick_two_weapon-weapon-trick-two-weapon-combat">Weapon Trick (Two-Weapon) (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 12</Link>, <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 8-9</Link></p>
<p>Choose one weapon trick option (one-handed weapon, polearm, ranged, two-handed weapon, two-weapon, or weapon and shield). You can perform weapon tricks in combat when armed appropriately for that option.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> You can use any weapon tricks relating to the chosen weapon option if you meet the trick's prerequisites and are proficient with any weapon or shield that you use as part of the trick.<br/><strong>Special:</strong> You can gain <Link to="/feat/weapon_trick">Weapon Trick</Link> multiple times. Each time you take the feat, it applies to a new weapon trick option. (These are listed as separate feats for reading convenience.)</p>
<p>These weapon tricks are common among the pirates of the Shackles, the Shoanti, and natives of Northern Casmaron and Garund. You can use these tricks only while wielding two weapons.</p>
<p><strong className="hl">Arm Bind</strong> (<Link to="/feat/two_weapon_defense">Two-Weapon Defense</Link>, <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link>): You can attempt a combat maneuver check to <Link to="/rule/disarm">disarm</Link> a foe even if the foe has no weapons. This functions as the disarm combat maneuver. If you succeed and the foe has no weapon, you ensnare an arm of your choice, preventing your foe from using that limb until the end of your next turn. A foe can take a standard action to free its arm.</p>
<p><strong className="hl">Dual Strike</strong> (<Link to="/feat/double_slice">Double Slice</Link>, <Link to="/feat/improved_vital_strike">Improved Vital Strike</Link>): As a standard action, you can make two attacks, one with each weapon you're wielding, applying the normal penalties for <Link to="/rule/two_weapon_fighting">two-weapon fighting</Link> to each.</p>
<p><strong className="hl">Off-Hand Opportunity</strong> (<Link to="/feat/combat_reflexes">Combat Reflexes</Link>): You can make one additional attack of opportunity each round with your off-hand weapon.</p>
<p><strong className="hl">Piercing Climb</strong> (Climb 8 ranks): You can use piercing weapons to climb as if your hands were free. You take a -4 penalty on Stealth checks while doing so. You can take 10 on such Climb checks even while distracted or endangered.</p>
<p><strong className="hl">Weapon Juggle</strong> (Two-Weapon Fighting): You can draw a weapon even while wielding two weapons. Doing so takes the same type of action as drawing that weapon normally would. As part of the action to draw the weapon, you must sheathe one of the two weapons you were wielding.</p>
</>};
const _weapon_trick_weapon_and_shield = {title: "Weapon Trick (Weapon and Shield)", jsx: <><h2 id="feat-weapon_trick_weapon_and_shield-weapon-trick-weapon-and-shield-combat">Weapon Trick (Weapon and Shield) (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 12</Link>, <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 8-9</Link></p>
<p>Choose one weapon trick option (one-handed weapon, polearm, ranged, two-handed weapon, two-weapon, or weapon and shield). You can perform weapon tricks in combat when armed appropriately for that option.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> You can use any weapon tricks relating to the chosen weapon option if you meet the trick's prerequisites and are proficient with any weapon or shield that you use as part of the trick.<br/><strong>Special:</strong> You can gain <Link to="/feat/weapon_trick">Weapon Trick</Link> multiple times. Each time you take the feat, it applies to a new weapon trick option. (These are listed as separate feats for reading convenience.)</p>
<p>These weapon tricks are common in Taldor, where they are used by rondelero fighters, and Lastwall, where they are taught in the Crusader's War College. You can use these tricks only while wielding a shield and a weapon you can wield in one hand.</p>
<p><strong className="hl">Confounding Shield</strong> (Bluff 5 ranks): You can always take 10 on Bluff checks to <Link to="/rule/feint">feint</Link> in combat.</p>
<p><strong className="hl">Feint and Bash</strong> (<Link to="/feat/improved_feint">Improved Feint</Link>, Bluff 10 ranks): When you feint successfully against a foe you threaten with your shield, that foe provokes an attack of opportunity from you. You can only perform a <Link to="/misc/shield_bash">shield bash</Link> with this attack of opportunity.</p>
<p><strong className="hl">Shielded View</strong> (Knowledge [dungeoneering] 1 rank): When you avert your eyes to avoid a <Link to="/umr/gaze">gaze</Link> attack, you have an 80% chance to avoid having to attempt a saving throw against the gaze.</p>
<p><strong className="hl">Warded Movement</strong> (<Link to="/feat/dodge">Dodge</Link>): As a swift action, you can choose a foe you can see. You can pass through that foe's threatened area without provoking attacks of opportunity from that foe this round. Once you target a foe with this trick, you can't target it again that day.</p>
<p><strong className="hl">Block and Counter</strong> (<Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link>): You can <Link to="/rule/ready">ready</Link> a standard action to block an attack with your shield, making an attack roll as though you were making a shield bash and using the result as your AC against that attack. If you successfully block the attack, you can attack that opponent with the weapon in your other hand as an immediate action.</p>
<p><strong className="hl">Shield Charge</strong> (<Link to="/feat/shield_focus">Shield Focus</Link>, <Link to="/feat/double_slice">Double Slice</Link>, base attack bonus +11): When you make a charge attack, you can attack twice - once with your shield and once with the weapon you are wielding in your other hand, applying the normal penalties for <Link to="/rule/two_weapon_fighting">fighting with two weapons</Link> to each.</p>
</>};
const _weapon_versatility = {title: "Weapon Versatility", jsx: <><h2 id="feat-weapon_versatility-weapon-versatility-combat">Weapon Versatility (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 25</Link></p>
<p>You can use your favored weapons in unconventional ways.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_focus">Weapon Focus</Link>, base attack bonus +1.<br/><strong>Benefit:</strong> When wielding a weapon with which you have Weapon Focus, you can shift your grip as a swift action so that your weapon deals bludgeoning, piercing, or slashing damage instead of the damage type normally dealt by that weapon. You may switch back to the weapon's normal damage type or another damage type as a swift action. If your base attack bonus is +5 or higher, using this feat is a free action instead.</p>
</>};
const _weather_eye = {title: "Weather Eye", jsx: <><h2 id="feat-weather_eye-weather-eye">Weather Eye</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 11</Link></p>
<p>Your constant attention to the natural order and your place in it has given you a keen sense for the ebb and flow of the seasons.<br/><strong>Prerequisites:</strong> Survival 3 ranks, must worship nature.<br/><strong>Benefit:</strong> You gain a +4 bonus on Survival checks made to predict the weather. You gain a +1 bonus on saving throws to avoid the effects of extreme <Link to="/rule/weather">weather</Link>.</p>
</>};
const _weathered_warrior = {title: "Weathered Warrior", jsx: <><h2 id="feat-weathered_warrior-weathered-warrior-combat">Weathered Warrior (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ranged_tactics_toolbox">Ranged Tactics Toolbox pg. 15</Link></p>
<p>You have a steady hand in any weather.<br/><strong>Prerequisites:</strong> <Link to="/feat/endurance">Endurance</Link>.<br/><strong>Benefit:</strong> In areas of strong or severe <Link to="/rule/wind">wind</Link> or when affected by wind effects or spells that penalize ranged attacks, you take only half the ranged attack penalty. You can make ranged attacks in windstorm-level winds at a -4 penalty.<br/><strong>Normal:</strong> Strong and severe winds impose -2 and -4 penalties on ranged attack rolls, respectively. Making ranged attacks in windstorms is impossible.</p>
</>};
const _welcome_pain = {title: "Welcome Pain", jsx: <><h2 id="feat-welcome_pain-welcome-pain">Welcome Pain</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_of_corruption">Faiths of Corruption pg. 25</Link></p>
<p>Your appreciation of pain grants you great stamina.<br/><strong>Prerequisites:</strong> <Link to="/feat/iron_will">Iron Will</Link>, worshiper of <Link to="/faith/zon_kuthon">Zon-Kuthon</Link>.<br/><strong>Benefit:</strong> Whenever you would be reduced to 0 or fewer hit points because of an ongoing or repeating damage effect (such as <Link to="/rule/bleed">bleed</Link>), you may make a last-ditch effort to shed the condition. If you succeed at a DC 25 Will save, you ignore the damage that would reduce you to 0 or fewer hit points that turn. The DC of each subsequent save made in this manner increases by 1. In addition, spells or abilities that have the pain descriptor deal only half damage to you (if any).</p>
</>};
const _well_prepared = {title: "Well-Prepared", jsx: <><h2 id="feat-well_prepared-well-prepared">Well-Prepared</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 173</Link></p>
<p>Somehow, you always seem to have the right tools or supplies close at hand.<br/><strong>Prerequisites:</strong> <Link to="/race/halfling">Halfling</Link>.<br/><strong>Benefit:</strong> Once per day, when confronted with a situation that calls for a particular mundane item of equipment, you may make a <Link to="/skill/sleight_of_hand">Sleight of Hand</Link> check with a DC of 10 plus the item's cost in gold pieces to "happen" to have such an item on your person. For example, having a <Link to="/eq-misc/crowbar">crowbar</Link> would be DC 12, whereas a flask of <Link to="/eq-weapon/acid">acid</Link> would be DC 20. The item must be something you can easily carry - if you are on foot and have only a <Link to="/eq-misc/backpack">backpack</Link>, for example, you could not have a large iron <Link to="/eq-misc/cauldron">cauldron</Link>. You cannot have magical items using this feat, nor can you have specific items, such as the key to a particular door. If you are stripped of your equipment or possessions, you lose the benefits of this feat until you have at least a day to resupply and "acquire" new items. You must pay for these items normally.<br/><strong>Special:</strong> At the GM's option, a character can substitute the <Link to="/skill/survival">Survival</Link> skill for Sleight of Hand with this feat. Such a choice is permanent.</p>
</>};
const _wheeling_charge = {title: "Wheeling Charge", jsx: <><h2 id="feat-wheeling_charge-wheeling-charge-combat">Wheeling Charge (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/cities_of_golarion">Cities of Golarion pg. 50</Link></p>
<p>Your mount moves with ease across battlefields.<br/><strong>Prerequisites:</strong> <Link to="/feat/mounted_combat">Mounted Combat</Link>, Ride 5 ranks, Lastwall affinity.<br/><strong>Benefit:</strong> When you are mounted and use the <Link to="/rule/charge">charge</Link> action, your mount can make one turn of up to 90 degrees as part of the move, as long as each part of the move is at least 10 feet. You may make an attack during any part of this move. Your total movement for the round can't exceed double your mounted speed. Allied creatures do not impede your charge, though you cannot attack from or end your move in an ally's space.<br/><strong>Normal:</strong> You cannot turn when making a charge.</p>
</>};
const _whip_mastery = {title: "Whip Mastery", jsx: <><h2 id="feat-whip_mastery-whip-mastery-combat">Whip Mastery (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 123</Link></p>
<p>Your superior expertise with this weapon does not provoke attacks of opportunity from your enemies.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_focus">Weapon Focus</Link> (whip), base attack bonus +2.<br/><strong>Benefit:</strong> You no longer provoke attacks of opportunity when attacking with a <Link to="/eq-weapon/whip">whip</Link>. You can deal lethal damage with a whip, although you can still deal nonlethal damage when you want. Further, you can deal damage with a whip despite a creature's armor bonus or natural armor bonus.<br/><strong>Normal:</strong> Attacking with a whip provokes attacks of opportunity as if you used a ranged weapon. A whip deals no damage to a creature that has an armor bonus of +1 or natural armor bonus of +3.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-whip_mastery--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-whip_mastery-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>When using a whip to deal nonlethal damage, as long as you have at least 1 stamina point in your stamina pool, the whip deals 1d8 points of nonlethal damage (1d6 for a Small whip). At the start of your turn, you can spend 2 stamina points to increase the damage die of the whip as if it were <Link to="/misc/one_size_category_larger">one size category larger</Link> for your next attack, regardless of whether you are dealing lethal or nonlethal damage. For nonlethal attacks, these two increases stack. This effect doesn't stack with other effects that treat the weapon as a larger size category unless they increase the actual size.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _whipcrack = {title: "Whipcrack", jsx: <><h2 id="feat-whipcrack-whipcrack-combat">Whipcrack (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 24</Link></p>
<p>You move an opponent and use his momentum to send him reeling across the battlefield.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_reposition">Improved Reposition</Link>.<br/><strong>Benefit:</strong> When you successfully <Link to="/rule/reposition">reposition</Link> an opponent, its movement need not remain within your reach, though once the opponent leaves your reach, its remaining movement must be in a straight line. This movement doesn't provoke attacks of opportunity unless you have the <Link to="/feat/greater_reposition">Greater Reposition</Link> feat.<br/><strong>Normal:</strong> The target of a reposition combat maneuver must remain within your reach at all times during its movement, except for the final 5 feet of movement, which can be to a space adjacent to your reach.</p>
</>};
const _whip_shot_deed = {title: "Whip-Shot Deed", jsx: <><h2 id="feat-whip_shot_deed-whip-shot-deed-grit">Whip-Shot Deed (Grit)</h2>
<p><strong>Sources</strong> <Link to="/source/magical_marketplace">Magical Marketplace pg. 22</Link></p>
<p>You can fire your weapon and strike with it at the same time.<br/><strong>Prerequisites:</strong> Grit class feature or <Link to="/feat/amateur_gunslinger">Amateur Gunslinger</Link> feat, <Link to="/deed/pistol_whip">pistol-whip</Link> deed.<br/><strong>Benefit:</strong> Whenever you use your <em>pistol-whip</em> deed, you can fire a single bullet from your firearm at the same time that you strike a foe with the butt of your firearm. You must spend a total of 2 grit points to use the <em>pistol-whip</em> deed in this way, and must still succeed at a ranged touch attack against the target of your <em>pistol-whip</em> deed to hit. You cannot use the <Link to="/misc/scatter">scatter</Link> weapon quality of a firearm when you use this feat.</p>
</>};
const _whip_slinger = {title: "Whip-Slinger", jsx: <><h2 id="feat-whip_slinger-whip-slinger-combat">Whip-Slinger (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion pg. 23</Link></p>
<p>You can use your sling as a sap to make attacks of opportunity.<br/><strong>Prerequisites:</strong> Proficient with <Link to="/eq-weapon/sling">sling</Link>.<br/><strong>Benefit:</strong> When wielding a sling, <Link to="/eq-weapon/double_sling">double sling</Link>, or <Link to="/eq-weapon/halfling_sling_staff">halfling sling staff</Link>, you threaten areas around you as normal and can make attacks of opportunity with the sling into these threatened areas. The sling deals 1d4 nonlethal bludgeoning damage (1d6 for a Medium wielder), threatens a critical hit on a 20, and deals &times;2 damage on a critical hit. If the sling isn't loaded with ammunition when you make an attack of opportunity, you take a -4 penalty on the attack roll.<br/><strong>Normal:</strong> Slings and double slings are ranged weapons, do not threaten areas, and cannot make attacks of opportunity. A halfling sling staff can be used as a simple melee weapon that deals bludgeoning damage equal to that of a club its size; as a melee weapon, it threatens areas normally and its wielder can make attacks of opportunity with it.</p>
</>};
const _whirling_hold = {title: "Whirling Hold", jsx: <><h2 id="feat-whirling_hold-whirling-hold-combat">Whirling Hold (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 23</Link></p>
<p>You lift your grappled foe from the ground and violently spin and disorient him.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_grapple">Improved Grapple</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>.<br/><strong>Benefit:</strong> When you succeed at a combat maneuver check to maintain a <Link to="/rule/grapple">grapple</Link>, instead of choosing to damage, move, pin, or tie up your opponent, you can lift and rapidly spin your opponent. At the end of the spin, you can place the opponent in any square adjacent to you. The opponent is <Link to="/misc/sickened">sickened</Link> for a number of rounds equal to your Strength or Dexterity modifier, whichever is higher.</p>
</>};
const _whirlwind_attack = {title: "Whirlwind Attack", jsx: <><h2 id="feat-whirlwind_attack-whirlwind-attack-combat">Whirlwind Attack (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 137</Link></p>
<p>You can strike out at every foe within reach.<br/><strong>Prerequisites:</strong> Dex 13, Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/dodge">Dodge</Link>, <Link to="/feat/mobility">Mobility</Link>, <Link to="/feat/spring_attack">Spring Attack</Link>, base attack bonus +4.<br/><strong>Benefit:</strong> When you use the full-attack action, you can give up your regular attacks and instead make one melee attack at your highest base attack bonus against each opponent within reach. You must make a separate attack roll against each opponent.</p>
<p>When you use the Whirlwind Attack feat, you also forfeit any bonus or extra attacks granted by other feats, spells, or abilities.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-whirlwind_attack--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-whirlwind_attack-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>When using this feat, you can spend stamina points to still take bonus or extra attacks granted by other feats, spells, or abilities. You must spend 5 stamina points per extra attack you take in this way. This combat trick allows you to make extra attacks to which you have access - it doesn't by itself grant extra attacks.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-whirlwind_attack--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>You can strike out at every foe within reach.<br/><strong>Prerequisites:</strong> Dex 13, Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/dodge">Dodge</Link>, <Link to="/feat/spring_attack">Spring Attack</Link>, base attack bonus +4.<br/><strong>Benefit:</strong> When you use the full-attack action, you can give up your regular attacks and instead make one melee attack at your highest base attack bonus against each opponent within reach. You must make a separate attack roll against each opponent.</p>
<p>When you use the Whirlwind Attack feat, you also forfeit any bonus or extra attacks granted by other feats, spells, or abilities.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _whispered_knowledge = {title: "Whispered Knowledge", jsx: <><h2 id="feat-whispered_knowledge-whispered-knowledge-faction">Whispered Knowledge (Faction)</h2>
<p><strong>Sources</strong> <Link to="/source/faction_guide">Faction Guide pg. 58</Link></p>
<p>You possess secret knowledge that enhances and helps perfect your undead form.<br/><strong>Prerequisites:</strong> Corporeal undead, <Link to="/rule/whispering_way">Whispering Way</Link> 15 TPA.<br/><strong>Benefit:</strong> Choose one of the following secrets:</p>
<blockquote>
<p><strong className="hl">Secret of Blood:</strong> After successfully dealing damage to a living creature with a melee attack, you can consume that creature's blood from your weapon as a swift action, gaining 1d8 <Link to="/rule/temporary_hit_points">temporary hit points</Link>, a +2 enhancement bonus to Strength, and a +1 bonus to your caster level. This lasts 10 minutes per Hit Die of your target, and otherwise acts as a <Link to="/spell/death_knell">death knell</Link> spell.</p>
<p><strong className="hl">Secret of Bone:</strong> Your bones harden and calcify. You gain DR 5/bludgeoning.</p>
<p><strong className="hl">Secret of Brains:</strong> As <em>secret of blood,</em> but you gain a +2 enhancement bonus to your Intelligence instead of Strength. This ability has no effect on mindless targets.</p>
<p><strong className="hl">Secret of the Grave:</strong> You can designate an unholy container for your remains, such as a coffin, canopic jar, or burial urn. When in this container and not taking any actions, you gain <Link to="/umr/fast_healing">fast healing</Link> 5.</p>
</blockquote>
<p><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take the feat, you learn a new secret.</p>
</>};
const _whispering_way_disciple = {title: "Whispering Way Disciple", jsx: <><h2 id="feat-whispering_way_disciple-whispering-way-disciple">Whispering Way Disciple</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 13</Link></p>
<p>Your research has gained the attention of the <Link to="/rule/whispering_way">Whispering Way</Link>, which rewards you with access to its libraries.<br/><strong>Prerequisites:</strong> <Link to="/feat/associate">Associate</Link> (Whispering Way).<br/><strong>Benefit:</strong> You can exploit lore acquired from the Whispering Way once per day to combine your own blood and a vial of <Link to="/eq-weapon/unholy_water">unholy water</Link> to create a potion of <Link to="/spell/cure_light_wounds">cure light wounds</Link> or a potion of <Link to="/spell/inflict_light_wounds">inflict light wounds</Link> as a full-round action. The blood loss from this transformation deals 1 point of Constitution damage to you. In addition, in any <Link to="/rule/the_settlement_stat_block">settlement</Link> that is the size of a small town or larger, you can always find scrolls of the following spells available for purchase regardless of their legality: <Link to="/spell/animate_dead">animate dead</Link>, <Link to="/spell/control_undead">control undead</Link>, <Link to="/spell/create_undead">create undead</Link>, <Link to="/spell/detect_undead">detect undead</Link>, <Link to="/spell/disrupt_undead">disrupt undead</Link>, <Link to="/spell/false_life">false life</Link>, <Link to="/spell/greater_false_life">greater false life</Link>, <Link to="/spell/ghoul_touch">ghoul touch</Link>, <Link to="/spell/lesser_animate_dead">lesser animate dead</Link>, <Link to="/spell/mass_repair_undead">mass repair undead</Link>, <Link to="/spell/repair_undead">repair undead</Link>, and <Link to="/spell/undead_anatomy_i">undead anatomy I-IV</Link>.</p>
</>};
const _wicked_valor = {title: "Wicked Valor", jsx: <><h2 id="feat-wicked_valor-wicked-valor">Wicked Valor</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_fiends">Blood of Fiends pg. 25</Link></p>
<p>The fiendish blood that courses through your body causes your wounds to heal faster than usual.<br/><strong>Prerequisites:</strong> Con 15, <Link to="/feat/diehard">Diehard</Link>, <Link to="/feat/endurance">Endurance</Link>, <Link to="/race/tiefling">tiefling</Link>.<br/><strong>Benefit:</strong> When you <Link to="/rule/regain_hit_points">regain hit points</Link> by resting, you heal double the normal amount of damage. This feat does not stack with items or effects that also affect the amount of damage you recover from while resting. This feat only functions with a full night's rest; complete bed rest is not affected by this feat.</p>
</>};
const _widen_spell = {title: "Widen Spell", jsx: <><h2 id="feat-widen_spell-widen-spell-metamagic">Widen Spell (Metamagic)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 137</Link></p>
<p>You can cast your spells so that they occupy a larger space.<br/><strong>Benefit:</strong> You can alter a <Link to="/misc/burst">burst, emanation, or spread</Link>-shaped spell to increase its area. Any numeric measurements of the spell's area increase by 100%. A widened spell uses up a spell slot three levels higher than the spell's actual level.</p>
<p>Spells that do not have an area of one of these four sorts are not affected by this feat.</p>
</>};
const _wild_flanking = {title: "Wild Flanking", jsx: <><h2 id="feat-wild_flanking-wild-flanking-betrayal-teamwork">Wild Flanking (Betrayal, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption pg. 21</Link></p>
<p>When flanking, you use your position to rain grievous blows upon a trapped foe, though you have little regard to the well-being of your flanking partner as you wildly hack away.<br/><strong>Prerequisites:</strong> <Link to="/feat/power_attack">Power Attack</Link>, base attack bonus +4.<br/><strong>Benefit:</strong> When you are <Link to="/rule/flanking">flanking</Link> an opponent with an ally who also possesses this feat, you can throw yourself into your attacks in such a way that your opponent takes extra damage, at the risk of these attacks striking your ally as well. When you choose to use this feat, check the results of your attack roll against both your opponent's AC and your ally's AC. If you hit your opponent, you deal bonus damage as though you were using Power Attack. If you hit your ally, the ally takes no damage from your attack except this bonus damage. It is possible to hit both your enemy and your abettor with one attack. Extra damage from this feat stacks with Power Attack.</p>
</>};
const _wild_growth_channel = {title: "Wild Growth Channel", jsx: <><h2 id="feat-wild_growth_channel-wild-growth-channel">Wild Growth Channel</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 119</Link></p>
<p>When you channel positive energy, you cause vines to grow and ensnare enemies.<br/><strong>Prerequisites:</strong> <Link to="/ability/channel_positive_energy">Channel positive energy</Link> class feature, <Link to="/domain/plant">Plant</Link> domain.<br/><strong>Benefit:</strong> By expending two additional uses when you channel energy, you cause the ground in the area of effect to erupt in a growth of vines. You create a number of vine growths (AC 10, 5 hp) equal to your Charisma modifier (minimum 1). Each growth of vines occupies 1 5-foot square of your choosing. As an immediate action when you use this ability, and again as a free action at the start of your turn, you can command the vines to wrap around the legs of a creature occupying the square. The creature must succeed at a Reflex save (DC = 10 + half your class level + your Charisma modifier) or become rooted to the spot. The vines last a number of rounds equal to your Charisma modifier (minimum 1). The ground must be composed of a material able to support plant life (such as soil).</p>
</>};
const _wild_growth_hex = {title: "Wild Growth Hex", jsx: <><h2 id="feat-wild_growth_hex-wild-growth-hex">Wild Growth Hex</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 119</Link></p>
<p>Hexing your enemies causes them to be ensnared in tangling vines.<br/><strong>Prerequisites:</strong> Hex class feature; <Link to="/patron/summer">summer</Link>, <Link to="/patron/thorns">thorns</Link>, or <Link to="/patron/woodlands">woodlands</Link> patron.<br/><strong>Benefit:</strong> When you gain this feat, choose one hex that you can use to affect no more than one opponent. If the target of your hex fails its saving throw to resist your hex, the square it occupies becomes overgrown with thorny plants that count as <Link to="/rule/difficult_terrain">difficult terrain</Link>. A creature moving in or out of the square must succeed at a Reflex save or Acrobatics check (DC = 10 + half your level + your Charisma modifier) or take 1d6 points of piercing damage and immediately end its movement. For every 5 by which the target fails its save against your hex, you can create 1 additional square of difficult terrain adjacent to any square the target occupies. The difficult terrain lasts a number of rounds equal to your Charisma modifier (minimum 1). The ground must be composed of a material able to support plant life (such as soil).</p>
</>};
const _wild_speaker = {title: "Wild Speaker", jsx: <><h2 id="feat-wild_speaker-wild-speaker">Wild Speaker</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 6</Link></p>
<p>The Bleaching enhances a gnome's ability to communicate with the natural world.<br/><strong>Prerequisites:</strong> Bleachling racial trait, <Link to="/race/gnome">gnome</Link>.<br/><strong>Benefit:</strong> You can use your <Link to="/spell/speak_with_animals">speak with animals</Link> spell-like ability at will.</p>
</>};
const _wild_speech = {title: "Wild Speech", jsx: <><h2 id="feat-wild_speech-wild-speech">Wild Speech</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 159</Link></p>
<p>You speak with the tongue of men and beasts.<br/><strong>Prerequisites:</strong> Druid level 6th, wild shape class feature.<br/><strong>Benefit:</strong> When using wild shape to take the form in which you cannot speak (such as an animal), you are able to speak normally in any language you know. This allows you to cast spells with verbal components, speak command words, and activate spell completion and spell trigger items. However, it does not give you the ability to cast spells requiring somatic components unless you also have the <Link to="/feat/natural_spell">Natural Spell</Link> feat, or cast spells with material components merged into your form.</p>
<p>When using wild shape to take the form of an animal, you may use <Link to="/spell/speak_with_animals">speak with animals</Link> to communicate with animals of your assumed form. This is a spell-like ability with a caster level equal to your druid level, and you may use it for a number of minutes per day equal to your druid level. These minutes do not have to be consecutive, but must be used in one-minute increments.</p>
</>};
const _wild_vigor = {title: "Wild Vigor", jsx: <><h2 id="feat-wild_vigor-wild-vigor">Wild Vigor</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 120</Link></p>
<p>The forces of nature bolster your vitality when you use wild shape.<br/><strong>Prerequisites:</strong> Wild shape class feature.<br/><strong>Benefit:</strong> A number of times per day equal to your Wisdom bonus (minimum 1), when you use wild shape, you can gain a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to your base attack bonus. These temporary hit points last for the duration of the wild shape or until they are lost.</p>
</>};
const _wilding = {title: "Wilding", jsx: <><h2 id="feat-wilding-wilding">Wilding</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 120</Link></p>
<p>You were touched by nature at an early age and share a kinship with wild creatures. Your body might bear animalistic features, such as bestial ears or a tail, or your presence may be subtly unlike that of others.<br/><strong>Prerequisites:</strong> Any neutral alignment, must be taken at 1st level.<br/><strong>Benefit:</strong> You gain the druid's <Link to="/ability/wild_empathy">wild empathy</Link> ability, using your character level as your druid level. If you have one or more levels in a class that grants wild empathy, you gain an additional +3 bonus on wild empathy checks. You are treated as an animal for the purpose of harmful mind-affecting effects that target animals (such as <Link to="/spell/charm_animal">charm animal</Link>).<br/><strong>Special:</strong> A character who has this feat can select the <Link to="/feat/animal_soul">Animal Soul</Link> or <Link to="/feat/aspect_of_the_beast">Aspect of the Beast</Link> feats without meeting the prerequisites.</p>
</>};
const _wilding_mind = {title: "Wilding Mind", jsx: <><h2 id="feat-wilding_mind-wilding-mind">Wilding Mind</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 120</Link></p>
<p>You can repress your conscious mind in favor of a primal state that helps you resist mental influence.<br/><strong>Prerequisites:</strong> Wis 13, <Link to="/feat/wilding">Wilding</Link>.<br/><strong>Benefit:</strong> Whenever you fail a saving throw against a fear or mind-affecting effect, you can take 1d3 points of Intelligence damage as an immediate action and reroll the saving throw. This damage cannot be reduced or avoided in any way. You must take the new result, even if it is worse.</p>
</>};
const _wilding_senses = {title: "Wilding Senses", jsx: <><h2 id="feat-wilding_senses-wilding-senses">Wilding Senses</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 120</Link></p>
<p>The wilderness speaks to you, giving you a preternatural sense of approaching danger.<br/><strong>Prerequisites:</strong> Wis 13, <Link to="/feat/wilding">Wilding</Link>.<br/><strong>Benefit:</strong> You gain a +2 bonus on <Link to="/skill/perception">Perception</Link> checks; this bonus increases to +4 when determining if you can act during a surprise round. If you have 10 or more ranks in Perception, this bonus increases to +4 (or +8 when determining whether you can act during a surprise round). This bonus does not stack with that granted by the <Link to="/feat/alertness">Alertness</Link> feat, though Wilding Senses counts as the Alertness feat for the purpose of fulfilling feat prerequisites and prestige class requirements.</p>
</>};
const _wilding_stride = {title: "Wilding Stride", jsx: <><h2 id="feat-wilding_stride-wilding-stride">Wilding Stride</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 120</Link></p>
<p>Your wild-hearted drive and honed physique allow you to move with great swiftness.<br/><strong>Prerequisites:</strong> Con 13, <Link to="/feat/wilding">Wilding</Link>.<br/><strong>Benefit:</strong> Your base speed increases by 10 feet. This does not stack with the fast movement class feature or similar effects, unless that class feature or effect provides an enhancement bonus.</p>
</>};
const _wilding_strike = {title: "Wilding Strike", jsx: <><h2 id="feat-wilding_strike-wilding-strike-combat">Wilding Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 120</Link></p>
<p>Filled with the might of nature, you need no weapons of steel or wood. Your fists and feet are as potent as any creation of the forge.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/wilding">Wilding</Link>.<br/><strong>Benefit:</strong> The damage die of your unarmed strikes increases to 1d6 (or 1d4 if you are Small). This does not stack with any other effects that increase the damage die of your unarmed strikes, including levels in classes such as monk. Increases to your actual size category (such as <Link to="/spell/enlarge_person">enlarge person</Link>) still increase your damage die as normal.</p>
</>};
const _will_of_giants = {title: "Will of Giants", jsx: <><h2 id="feat-will_of_giants-will-of-giants">Will of Giants</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_91_battle_of_bloodmarch_hills">Pathfinder #91: Battle of Bloodmarch Hills pg. 70</Link></p>
<p>You are no mere humanoid, to be toyed with by petty enchantments.<br/><strong>Prerequisites:</strong> Wis 14, <Link to="/feat/iron_will">Iron Will</Link>, giant subtype.<br/><strong>Benefit:</strong> You gain immunity to enchantment effects that target only humanoids, such as <Link to="/spell/charm_person">charm person</Link> and <Link to="/spell/hold_person">hold person</Link>.</p>
</>};
const _willing_accomplice = {title: "Willing Accomplice", jsx: <><h2 id="feat-willing_accomplice-willing-accomplice">Willing Accomplice</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 95</Link></p>
<p>Your well-placed support can aid friends and allies in maintaining their most precious secrets.<br/><strong>Prerequisites:</strong> Cha 13, Bluff 3 ranks, Sense Motive 1 rank.<br/><strong>Benefit:</strong> As a standard action, you can attempt a Bluff check to aid another's Disguise check. In addition, when attempting such a check to aid a vigilante ally in maintaining that ally's social identity, a successful check grants that ally a +5 bonus instead of the normal +2.</p>
</>};
const _willing_death = {title: "Willing Death", jsx: <><h2 id="feat-willing_death-willing-death-origin">Willing Death (Origin)</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 17</Link></p>
<p>You might have been a soldier in an army, a self-sacrificing lover, or a hero who rushed in where even angels feared to tread. You died because you valued someone else's life above your own.<br/><strong>Prerequisites:</strong> <Link to="/race/duskwalker">Duskwalker</Link>.<br/><strong>Benefit:</strong> Twice per day, when an ally within 30 feet would die as a result of an attack or failing a saving throw, as an immediate action you can redirect the damage and effects to yourself. This functions as <Link to="/spell/paladins_sacrifice">paladin's sacrifice</Link>. At 11th level, you can use this feat two additional times per day.</p>
</>};
const _wily_warrior = {title: "Wily Warrior", jsx: <><h2 id="feat-wily_warrior-wily-warrior-story">Wily Warrior (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/spymasters_handbook">Spymaster's Handbook pg. 17</Link></p>
<p>Those who observe your imposing demeanor assume muscle is your sole advantage, but you prove them wrong every time.<br/><strong>Prerequisites:</strong> Bluff 1 rank, Sense Motive 1 rank, base attack bonus +1, or you must have the Military Strategist <Link to="/rule/spymaster_bg">espionage background</Link>.<br/><strong>Benefit:</strong> Once per day, you can use your ranks in Sense Motive in place of your total Will saving throw modifier when attempting a Will save. You must decide to use this ability prior to attempting the saving throw.<br/><strong>Goal:</strong> Thwart an appropriate number of challenging foes after getting a negative hunch about them when they attempted to deceive you or after ambushing them.<br/><strong>Completion Benefit:</strong> The DC of Bluff and Intimidate checks attempted against you increase by 5.</p>
</>};
const _wind_leaper = {title: "Wind Leaper", jsx: <><h2 id="feat-wind_leaper-wind-leaper-conduit">Wind Leaper (Conduit)</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 33</Link></p>
<p>Energies from the Plane of Air ease your movements and let you make mighty leaps.<br/><strong>Prerequisites:</strong> Knowledge (planes) 3 ranks.<br/><strong>Benefit:</strong> As a swift action, you can wrap your body in airy energies. This reduces your effective weight by half. While this ability is active, you gain a circumstance bonus on <Link to="/skill/acrobatics">Acrobatics</Link> checks equal to half your ranks in Knowledge (planes), you are always treated as having a running start when attempting Acrobatics checks to jump, and your Acrobatics checks to high jump are treated as long jumps for the purpose of determining the DC.</p>
<p>You can use this feat's benefit for a number of rounds per day equal to your ranks in Knowledge (planes). These rounds need not be consecutive.</p>
</>};
const _wind_rider = {title: "Wind Rider", jsx: <><h2 id="feat-wind_rider-wind-rider">Wind Rider</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 29</Link></p>
<p>You have trained yourself to move and fight in strong winds, allowing you to use their elemental power to boost your own speed.<br/><strong>Prerequisites:</strong> Acrobatics or Fly 3 ranks.<br/><strong>Benefit:</strong> When flying within strong winds, you gain a +15 foot bonus to your fly speed. For every <Link to="/rule/wind">wind</Link> strength category above strong, you gain an additional +15 foot bonus to your fly speed (for a total of +30 feet in severe winds, +45 feet in a windstorm, and +60 feet in tornadoes). This feat does not give you any bonuses on Fly or Strength checks to determine if you are potentially checked or blown away.</p>
</>};
const _wind_song = {title: "Wind Song", jsx: <><h2 id="feat-wind_song-wind-song">Wind Song</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 19</Link></p>
<p>You have learned to play haunting, captivating melodies similar to those of the eerie Painted Flutes canyon. Like an echo, the wind carries the sound and magic of your music much farther than it would normally reach.<br/><strong>Prerequisites:</strong> Perform (wind) 5 ranks; <Link to="/ability/bardic_performance">bardic performance</Link> or <Link to="/ability/raging_song">raging song</Link> class feature.<br/><strong>Benefit:</strong> Three times per day while you are using a wind instrument to play a bardic performance or raging song, you can spend an extra round of performance at the start of your performance and choose a square within 120 feet. Strange echoes carry your music, and for the purpose of determining which creatures are affected by your performance, your performance counts as originating from that square rather than from your location. You cannot change the square from which the music originates until you end your performance. If you move beyond 120 feet from the chosen square, the performance immediately ends.</p>
</>};
const _wind_stance = {title: "Wind Stance", jsx: <><h2 id="feat-wind_stance-wind-stance-combat">Wind Stance (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 137</Link></p>
<p>Your erratic movements make it difficult for enemies to pinpoint your location.<br/><strong>Prerequisites:</strong> Dex 15, <Link to="/feat/dodge">Dodge</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> If you move more than 5 feet this turn, you gain 20% <Link to="/rule/concealment">concealment</Link> for 1 round against ranged attacks.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-wind_stance--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-wind_stance-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>When using this feat, you can spend 5 stamina points to gain 20% concealment for 1 round against all attacks (not just ranged attacks).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _wingclipper = {title: "Wingclipper", jsx: <><h2 id="feat-wingclipper-wingclipper-combat">Wingclipper (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 25</Link></p>
<p>Your attacks can prevent winged opponents from flying.<br/><strong>Prerequisites:</strong> Base attack bonus +9.<br/><strong>Benefit:</strong> Whenever you confirm a critical hit against an opponent that uses wings to fly, you can forgo the extra critical damage to instead prevent it from flying for a number of rounds equal to twice the critical multiplier of your attack. Opponents that are flying at the time of the critical effect must succeed at a DC 20 Fly check to avoid taking <Link to="/rule/falling">falling</Link> damage.</p>
</>};
const _wingover = {title: "Wingover", jsx: <><h2 id="feat-wingover-wingover-monster">Wingover (Monster)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_rpg_bestiary">Pathfinder RPG Bestiary pg. 316</Link></p>
<p>This creature can make turns with ease while flying.<br/><strong>Prerequisites:</strong> Fly speed.<br/><strong>Benefit:</strong> Once each round, a creature with this feat can turn up to 180 degrees as a free action without making a <Link to="/skill/fly">Fly</Link> skill check. This free turn does not consume any additional movement from the creature.<br/><strong>Normal:</strong> A flying creature can turn up to 90 degrees by making a DC 15 Fly skill check and expending 5 feet of movement. A flying creature can turn up to 180 degrees by making a DC 20 Fly skill check and expending 10 feet of movement.</p>
</>};
const _wings_of_air = {title: "Wings of Air", jsx: <><h2 id="feat-wings_of_air-wings-of-air">Wings of Air</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 159</Link></p>
<p>The winds lift you, carrying you where you want to go.<br/><strong>Prerequisites:</strong> <Link to="/feat/airy_step">Airy Step</Link>, character level 9th, <Link to="/race/sylph">sylph</Link>.<br/><strong>Benefit:</strong> Your bonus on saves against effects with the air or electricity descriptors and effects that deal electricity damage increases to +4. In addition, you gain a supernatural fly speed equal to your base speed (good maneuverability). You may only fly with this ability when wearing light armor or no armor.</p>
</>};
const _wings_of_the_androsphinx = {title: "Wings of the Androsphinx", jsx: <><h2 id="feat-wings_of_the_androsphinx-wings-of-the-androsphinx-combat">Wings of the Androsphinx (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands pg. 13</Link></p>
<p>You can reshape the kinetic energy of foes' charges.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_reposition">Improved Reposition</Link>, base attack bonus +1 or monk level 1st.<br/><strong>Benefit:</strong> You gain a +2 bonus to AC against <Link to="/rule/charge">charge</Link> attacks. If a creature charges you and fails its attack roll, as an immediate action you can attempt a <Link to="/rule/reposition">reposition</Link> combat maneuver to reposition that foe. If you use a <Link to="/rule/readied_action">readied action</Link> to attack a creature charging you, you can roll to attack and then attempt to reposition that creature as a free action before it resolves its charge attack.<br/><strong>Note:</strong> A monk can take this feat as a bonus feat at 1st level. To benefit from this feat, monks must have both hands free and be capable of delivering an unarmed strike.</p>
</>};
const _winters_strike = {title: "Winter's Strike", jsx: <><h2 id="feat-winters_strike-winters-strike-combat">Winter's Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 159</Link></p>
<p>Your attacks afflict your foes with the relentless fatigue of a winter storm.<br/><strong>Prerequisites:</strong> <Link to="/feat/nature_magic">Nature Magic</Link> or the ability to cast druid or ranger spells; <Link to="/feat/vital_strike">Vital Strike</Link>, Knowledge (nature) 5 ranks.<br/><strong>Benefit:</strong> A number of times per day equal to your Wisdom modifier (minimum 1), when you use Vital Strike (or <Link to="/feat/improved_vital_strike">Improved Vital Strike</Link> or <Link to="/feat/greater_vital_strike">Greater Vital Strike</Link>), your strike saps the strength of your opponent. The creature hit must succeed at a Fortitude save (DC = 10 + 1/2 your character level + your Wisdom modifier) or become fatigued for a number of rounds equal to your Wisdom modifier (minimum 1). You can choose to use this ability as a free action after you hit the target with the attack. This is a supernatural ability.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-winters_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-winters_strike-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>When using this feat, you can spend up to 5 stamina points to increase the DC of the effect by an amount equal to the number of stamina points you spent.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _witch_knife = {title: "Witch Knife", jsx: <><h2 id="feat-witch_knife-witch-knife">Witch Knife</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 159</Link></p>
<p>You empower your witch spells by incorporating the use of a special ceremonial knife during your castings.<br/><strong>Prerequisites:</strong> <Link to="/class/witch">Witch</Link> class.<br/><strong>Benefit:</strong> Each day, when you prepare your spells, you can select a masterwork or magical <Link to="/eq-weapon/dagger">dagger</Link>, transforming it into a <em>witch knife,</em> which serves as an additional focus component for witch patron spells. Add +1 to the DC of all your patron spells.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-witch_knife--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Witch Knife</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 77</Link><br/>Your <em>witch knife</em> is as much an extension of your body as it is an extension of your power.<br/><strong>Prerequisites:</strong> Witch Knife.<br/><strong>Benefit:</strong> You can use your <em>witch knife</em> as an additional focus component for all your witch spells, not just your patron spells, adding 1 to their DC. This bonus stacks with the bonus to patron spells granted by Witch Knife, granting your patron spells a total +2 bonus to their DC. Additionally, the hand holding the <em>witch knife</em> is still considered free for the purpose of casting spells and delivering touch attacks.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _witchbreaker = {title: "Witchbreaker", jsx: <><h2 id="feat-witchbreaker-witchbreaker-combat">Witchbreaker (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 120</Link>, <Link to="/source/people_of_the_north">People of the North pg. 24</Link></p>
<p>You are trained to be resilient to and disrupt the magic of hags and witches.<br/><strong>Prerequisites:</strong> <Link to="/feat/iron_will">Iron Will</Link>.<br/><strong>Benefit:</strong> You gain a +2 bonus on saving throws against the hexes, spells, spell-like abilities, and supernatural abilities of <Link to="/family/hag">hags</Link> and <Link to="/class/witch">witches</Link>. In addition, whenever you confirm a critical hit against a hag or a witch, any of your allies affected by a mind-affecting effect from that creature can attempt a new saving throw against the effect as an immediate action.</p>
</>};
const _witty_feint = {title: "Witty Feint", jsx: <><h2 id="feat-witty_feint-witty-feint">Witty Feint</h2>
<p><strong>Sources</strong> <Link to="/source/gnomes_of_golarion">Gnomes of Golarion pg. 31</Link></p>
<p>Your blending of conversation and martial prowess makes it difficult for opponents to slip past your guard.<br/><strong>Prerequisites:</strong> Bluff 1 rank, weapon training class feature, <Link to="/race/gnome">gnome</Link>.<br/><strong>Benefit:</strong> When you successfully <Link to="/rule/feint">feint</Link> against an opponent in combat, instead of denying the opponent his Dexterity bonus, you may gain a dodge bonus to your AC against his attacks. This bonus is equal to your weapon training bonus for your current weapon. The bonus lasts until combat ends, you switch opponents, or you switch to a different weapon, whichever comes first.</p>
</>};
const _wolf_rider = {title: "Wolf Rider", jsx: <><h2 id="feat-wolf_rider-wolf-rider">Wolf Rider</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 120</Link></p>
<p>Others can keep their horses. You know that wolves are better mounts.<br/><strong>Prerequisites:</strong> <Link to="/feat/undersized_mount">Undersized Mount</Link> or effective level 7th in the class that grants the mount or divine bond (mount) class feature; Knowledge (nature) 1 rank; mount or divine bond (mount) class feature.<br/><strong>Benefit:</strong> You can select a <Link to="/companion/wolf">wolf</Link> in place of the normal mount available via your mount or divine bond (mount) class feature. In addition, Knowledge (nature) is always a class skill for you.</p>
</>};
const _wolf_savage = {title: "Wolf Savage", jsx: <><h2 id="feat-wolf_savage-wolf-savage-combat">Wolf Savage (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 120</Link>, <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 25</Link></p>
<p>You savage your foes so badly that they can become supernaturally disfigured.<br/><strong>Prerequisites:</strong> Wis 17, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/wolf_style">Wolf Style</Link>, <Link to="/feat/wolf_trip">Wolf Trip</Link>, Knowledge (nature) 9 ranks.<br/><strong>Benefit:</strong> While using Wolf Style, when you deal at least 10 points of damage to a <Link to="/rule/prone">prone</Link> opponent with a natural weapon or an unarmed strike, as a swift action you can savage that creature. When you do, your opponent must succeed at a Fortitude save (DC = 10 + half your character level + your Wisdom modifier). If the target fails the saving throw, it takes either 1d4 Charisma damage or 1d4 Constitution damage, or it becomes <Link to="/misc/fatigued">fatigued</Link> (your choice). Ability score damage dealt with this ability cannot equal or exceed the victim's actual ability score total.</p>
</>};
const _wolf_style = {title: "Wolf Style", jsx: <><h2 id="feat-wolf_style-wolf-style-combat-style">Wolf Style (Combat, Style)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 121</Link>, <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 25</Link></p>
<p>While in this style, you hamper foes that turn their backs on you.<br/><strong>Prerequisites:</strong> Wis 13, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, Knowledge (nature) 3 ranks.<br/><strong>Benefit:</strong> While using this style, whenever you deal at least 10 points of damage to a foe with an attack of opportunity, that foe's base speed decreases by 5 feet until the end of its next turn. For every 10 points of damage your attack deals beyond 10, the foe's base speed decreases by an additional 5 feet. If the penalty meets or exceeds the total base speed of the foe, you can attempt to <Link to="/rule/trip">trip</Link> the foe as a free action after the attack of opportunity is resolved.</p>
</>};
const _wolf_trip = {title: "Wolf Trip", jsx: <><h2 id="feat-wolf_trip-wolf-trip-combat">Wolf Trip (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 121</Link>, <Link to="/source/blood_of_the_moon">Blood of the Moon pg. 25</Link></p>
<p>You have studied the manner in which wolves bring down their prey.<br/><strong>Prerequisites:</strong> Wis 15, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/wolf_style">Wolf Style</Link>, Knowledge (nature) 6 ranks.<br/><strong>Benefit:</strong> While using Wolf Style, you gain a +2 bonus when you attempt a <Link to="/rule/trip">trip</Link> combat maneuver as part of an attack of opportunity. Whenever you successfully trip a creature, as a free action you can choose an available space that is both adjacent to you and the creature's original space for the tripped creature to land <Link to="/rule/prone">prone</Link> in.</p>
</>};
const _wood_crafter = {title: "Wood Crafter", jsx: <><h2 id="feat-wood_crafter-wood-crafter">Wood Crafter</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 121</Link></p>
<p>Eschewing the use of metals in your craft, you excel at crafting armor from wood.<br/><strong>Prerequisites:</strong> Craft (armor) 3 ranks, Knowledge (nature) 3 ranks.<br/><strong>Benefit:</strong> You gain a +4 bonus on Craft (armor) checks to create armor and shields from wood or special materials containing wood (such as <Link to="/eq-material/darkwood">darkwood</Link>). If you succeed at the check by 5 or more, you decrease the cost to make the item by 10%.</p>
</>};
const _woodland_wraith = {title: "Woodland Wraith", jsx: <><h2 id="feat-woodland_wraith-woodland-wraith-combat">Woodland Wraith (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 121</Link></p>
<p>You put the terrain between yourself and your opponents to avoid attacks.<br/><strong>Prerequisites:</strong> Dex 15, <Link to="/feat/dodge">Dodge</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> If you take two actions to move or a <Link to="/rule/withdraw">withdrawal</Link> action in a turn while starting or ending your movement in either naturally occurring <Link to="/rule/difficult_terrain">difficult terrain</Link> (bushes, brambles, etc.) or a space with a natural object providing at least partial <Link to="/rule/cover">cover</Link> (a tree, rock, etc.), you gain <Link to="/rule/concealment">concealment</Link> until you attack, until you move out of that space, or until the end of your next turn, whichever occurs first.</p>
</>};
const _word_of_healing = {title: "Word of Healing", jsx: <><h2 id="feat-word_of_healing-word-of-healing">Word of Healing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 159</Link></p>
<p>Using the same divine energy as your lay on hands ability, you can heal others at a distance.<br/><strong>Prerequisites:</strong> <Link to="/ability/lay_on_hands">Lay on hands</Link> class feature.<br/><strong>Benefit:</strong> You may use your lay on hands to heal another creature at a range of 30 feet as a standard action that does not provoke an attack of opportunity. You must be able to speak and have a free hand to use this ability. The target heals half the amount they would have healed if you had touched them, but gains the benefits of your mercies as normal.</p>
</>};
const _worldwound_walker = {title: "Worldwound Walker", jsx: <><h2 id="feat-worldwound_walker-worldwound-walker">Worldwound Walker</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_purity">Champions of Purity pg. 23</Link></p>
<p>Your purity always remains a blessing, even when you're surrounded by creatures that despise it.<br/><strong>Prerequisites:</strong> 5 or more Hit Dice, good alignment.<br/><strong>Benefit:</strong> You can alter the essence of your being to lessen the effects of spells designed to harm good creatures. When affected by spells and effects that behave differently according to alignment (such as <Link to="/spell/unholy_ward">unholy ward</Link> or <Link to="/spell/protection_from_good">protection from good</Link>), you can choose whether you are considered good or neutral. This ability does not actually change your alignment or fool divinations, nor does it permit you to overcome alignment requirements for the use of magic items, class abilities, and so on.</p>
</>};
const _worst_case_jinx = {title: "Worst Case Jinx", jsx: <><h2 id="feat-worst_case_jinx-worst-case-jinx">Worst Case Jinx</h2>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion pg. 27</Link></p>
<p>Your jinxes hinder beneficial spells.<br/><strong>Prerequisites:</strong> Knowledge (arcana) 5 ranks, Halfling Jinx trait.<br/><strong>Benefit:</strong> Beneficial variable effects on a jinxed target (such as <Link to="/spell/aid">aid</Link>, <Link to="/main/cure_spells">cure spells</Link>, <Link to="/spell/false_life">false life</Link>, the variable ability damage cured by <Link to="/spell/lesser_restoration">lesser restoration</Link>, and so on) always result in the minimum possible amount for the effect. For example, a 5th-level cleric casting <Link to="/spell/cure_serious_wounds">cure serious wounds</Link> on the target only heals 8 hit points (the minimum for 3d8+5).</p>
</>};
const _wounded_paw_gambit = {title: "Wounded Paw Gambit", jsx: <><h2 id="feat-wounded_paw_gambit-wounded-paw-gambit-combat-teamwork">Wounded Paw Gambit (Combat, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 159</Link></p>
<p>Your enemy sees you as an easy mark, but doesn't notice your allies poised to shoot.<br/><strong>Prerequisites:</strong> <Link to="/feat/broken_wing_gambit">Broken Wing Gambit</Link>, Bluff 5 ranks.<br/><strong>Benefit:</strong> Whenever you use Broken Wing Gambit and an opponent attacks you as a result, each ally who has this feat and is within 30 feet of that opponent can attempt a ranged attack against it as an immediate action. The ally's ranged weapon must be in hand, loaded, and ready to be fired or thrown in order to make this attack possible.</p>
<p>An ally who has this feat and Broken Wing Gambit can instead use Broken Wing Gambit to attempt an attack of opportunity against the foe, but cannot attempt both that attack of opportunity and this ranged attack.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-wounded_paw_gambit--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-wounded_paw_gambit-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 135</Link><br/>When you make a ranged attack granted by this feat, you can spend 5 stamina points to make that ranged attack as an attack of opportunity instead of as an immediate action. You can still use this feat to make an extra attack only once per round.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _wrest_charge = {title: "Wrest Charge", jsx: <><h2 id="feat-wrest_charge-wrest-charge">Wrest Charge</h2>
<p><strong>Sources</strong> <Link to="/source/technology_guide">Technology Guide pg. 7</Link></p>
<p>You can extract a charge from otherwise depleted technology.<br/><strong>Prerequisites:</strong> Disable Device 5 ranks, Knowledge (engineering) 5 ranks<br/><strong>Benefit:</strong> With a successful DC 20 Disable Device check, you can jury-rig a depleted (but not destroyed) <Link to="/tech-misc/battery">battery</Link> so it provides 1 more charge. Using this charge or failing your check by 5 or more permanently depletes the battery.</p>
<p>You can attempt the same check to add 1 last charge to a discharged piece of <Link to="/rule/timeworn_technology">timeworn technology</Link>. Regardless of the outcome, no other attempts can be made, even by another person. Using this feat takes 1 minute. You can attempt to wrest a charge as a move action by taking a -10 penalty on your check. This feat does not stack with the <Link to="/arc-gunslinger/techslinger">charge recycling deed</Link>.</p>
</>};
const _wretched_curator = {title: "Wretched Curator", jsx: <><h2 id="feat-wretched_curator-wretched-curator-story">Wretched Curator (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 9</Link></p>
<p>Some fools fear the written word, but you that understand knowledge all knowledge is a valuable tool, and restricting it out of superstition is abominable in your eyes.<br/><strong>Prerequisites:</strong> You must have purchased a scroll or spellbook containing a spell with the <Link to="/spelldef/evil">evil</Link> descriptor in a place where such dealings are illegal, or must have the Secret Society Inductee (growing up) or Diabolical Upbringing (early events) <Link to="/rule/bad_beginnings">background</Link>.<br/><strong>Benefit:</strong> You can always purchase potions and scrolls of spells with the evil descriptor at a 10% discount, even if they are not normally available in a settlement because of its size or the local laws. You gain a +4 bonus on Knowledge (arcana), Spellcraft, and Use Magic Device checks related to spells with the evil descriptor or evil written works.<br/><strong>Goal:</strong> You must own scrolls of spells with the evil descriptor or tomes of forbidden lore worth a total of 50 gp per character level, and be the primary caster of a successful <Link to="/rule/occult_rituals">occult ritual</Link> of at least 5th level that has the evil descriptor.<br/><strong>Completion Benefit:</strong> Every time you cast a spell with the evil descriptor, you can remove that descriptor from the spell and treat yourself as a neutral-aligned caster for the purpose of determining the spell's effects, circumventing defenses such as <Link to="/spell/protection_from_evil">protection from evil</Link> and preventing detection via <Link to="/spell/detect_evil">detect evil</Link> and similar effects. If you cast a spell with the evil descriptor and do not remove that descriptor, you instead gain 2 <Link to="/rule/temporary_hit_points">temporary hit points</Link> per spell level. These temporary hit points last for 1 hour.</p>
</>};
const _wrist_grab = {title: "Wrist Grab", jsx: <><h2 id="feat-wrist_grab-wrist-grab-combat">Wrist Grab (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/martial_arts_handbook">Martial Arts Handbook pg. 22</Link></p>
<p>When an enemy overextends to attack you, you quickly catch its arm and knock its weapon loose.<br/><strong>Prerequisites:</strong> Dex 13, Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, <Link to="/feat/improved_disarm">Improved Disarm</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> When an opponent's attack misses you by 5 or more, you can attempt a <Link to="/rule/disarm">disarm</Link> combat maneuver check against that foe as an immediate action.</p>
</>};
const _wyvaran_spellcasting = {title: "Wyvaran Spellcasting", jsx: <><h2 id="feat-wyvaran_spellcasting-wyvaran-spellcasting">Wyvaran Spellcasting</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_dragons">Legacy of Dragons pg. 19</Link></p>
<p>Your unique physiology makes you particularly adept at wielding draconic magic.<br/><strong>Prerequisites:</strong> Knowledge (arcana) 6 ranks, <Link to="/race/wyvaran">wyvaran</Link>.<br/><strong>Benefit:</strong> Select one spell you can cast that you gained through your <Link to="/sorcbloodline/draconic">draconic</Link> sorcerer bloodline, <Link to="/blrgbloodline/draconic">draconic</Link> bloodrager bloodline, the <Link to="/domain/scalykind">Scalykind</Link> domain, or the <Link to="/domain/dragon">Dragon</Link> subdomain. It must be at least 1 spell level lower than the highest-level spell you can cast. You can cast this spell as a spell-like ability twice per day.</p>
</>};
const _wyvern_fury_style = {title: "Wyvern Fury Style", jsx: <><h2 id="feat-wyvern_fury_style-wyvern-fury-style-combat-style">Wyvern Fury Style (Combat, Style)</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_dragons">Legacy of Dragons pg. 21</Link></p>
<p>You can combine sweeping attacks with a whip and quick stabs with a blade, imitating a wyvern's powerful bite and tail tipped with a stinger.<br/><strong>Prerequisites:</strong> <Link to="/feat/exotic_weapon_proficiency">Exotic Weapon Proficiency</Link> (whip), Acrobatics 3 ranks, brawler's flurry class feature or flurry of blows class feature.<br/><strong>Benefit:</strong> While using this style, you can make attacks with a <Link to="/eq-weapon/dagger">dagger</Link>, <Link to="/eq-weapon/punching_dagger">punching dagger</Link>, <Link to="/eq-weapon/scorpion_whip">scorpion whip</Link>, <Link to="/eq-weapon/spiked_gauntlet">spiked gauntlet</Link>, or <Link to="/eq-weapon/whip">whip</Link> when using a flurry of blows or brawler's flurry. Only one of these attacks can be made with a whip or scorpion whip.</p>
</>};
const _wyvern_sting = {title: "Wyvern Sting", jsx: <><h2 id="feat-wyvern_sting-wyvern-sting-combat">Wyvern Sting (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_dragons">Legacy of Dragons pg. 21</Link></p>
<p>You can use your whip like a wyvern's sting, forcing foes to give it their undivided attention.<br/><strong>Prerequisites:</strong> <Link to="/feat/exotic_weapon_proficiency">Exotic Weapon Proficiency</Link> (whip), <Link to="/feat/wyvern_fury_style">Wyvern Fury Style</Link>, Acrobatics 6 ranks, brawler's flurry class feature or flurry of blows class feature.<br/><strong>Benefit:</strong> While using Wyvern Fury Style, if you successfully attack a foe with a <Link to="/eq-weapon/whip">whip</Link> or <Link to="/eq-weapon/scorpion_whip">scorpion whip</Link>, as a swift action you can choose one ally. Until the beginning of your next turn, that ally can leave spaces threatened by that foe without provoking an attack of opportunity from the foe.</p>
</>};
const _wyvern_wing = {title: "Wyvern Wing", jsx: <><h2 id="feat-wyvern_wing-wyvern-wing-combat">Wyvern Wing (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_dragons">Legacy of Dragons pg. 21</Link></p>
<p>Like a wyvern on the wing, you command a fluid style that enables you to make attacks while moving.<br/><strong>Prerequisites:</strong> <Link to="/feat/exotic_weapon_proficiency">Exotic Weapon Proficiency</Link> (whip), <Link to="/feat/wyvern_fury_style">Wyvern Fury Style</Link>, <Link to="/feat/wyvern_sting">Wyvern Sting</Link>, Acrobatics 10 ranks, brawler's flurry class feature or flurry of blows class feature.<br/><strong>Benefit:</strong> While using the Wyvern Style feat, if you use flurry of blows or brawler's flurry and take a 5-foot step, you can take an additional 5-foot step. You can take this extra 5-foot step only between two attacks in your flurry, but you can take both your 5-foot steps consecutively without making an attack between them.</p>
</>};
const _xenoglossy = {title: "Xenoglossy", jsx: <><h2 id="feat-xenoglossy-xenoglossy">Xenoglossy</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 141</Link></p>
<p>People everywhere share a common tongue; they just don't always remember it.<br/><strong>Prerequisites:</strong> Int 13, Linguistics 3 ranks.<br/><strong>Benefit:</strong> With a successful DC 25 Linguistics check, you can speak with a single individual with whom you share no common languages. You cannot take 10 on this check, nor can anyone aid you. You believe you are speaking your native language, and the listener believes you are speaking its native language; however, to everyone else able to hear you, you sound like you are speaking gibberish. Creatures that have <em>truespeech</em> or that are under the effects of <Link to="/spell/tongues">tongues</Link> can understand Xenoglossy, and other creatures who succeed at a DC 25 <Link to="/skill/linguistics">Linguistics</Link> check can pick up the gist of what you are saying. Xenoglossy lasts for the length of the conversation or for 1 minute per level, whichever is shorter. You can use Xenoglossy again to continue a longer conversation, and you gain a +2 on Linguistics checks to use Xenoglossy to communicate with someone with whom you previously communicated using this feat. If you fail a Xenoglossy check, you can't use the Xenoglossy feat to attempt further communication with that creature until you gain additional ranks in Linguistics.</p>
</>};
const _yai_mimic_spell = {title: "Yai-Mimic Spell", jsx: <><h2 id="feat-yai_mimic_spell-yai-mimic-spell-metamagic">Yai-Mimic Spell (Metamagic)</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 23</Link></p>
<p>You have studied the magical nature of giant oni and can use your spells to imitate their esoteric features.<br/><strong>Prerequisites:</strong> Int 15, <Link to="/feat/still_spell">Still Spell</Link>.<br/><strong>Benefit:</strong> You can modify a ray spell to issue from the center of your forehead, where the third eye would be on a <Link to="/family/oni">yai</Link>. This spell doesn't require somatic components. When the spell is cast, you gain <Link to="/umr/regeneration">regeneration</Link> 1 for a number of rounds equal to the original level of the spell. This regeneration can't regrow lost body parts or reattach severed limbs. Fire or acid damage suppresses this regeneration for 1 round, which counts against the total duration of the regeneration effect. A yai-mimic spell uses up a spell slot 3 levels higher than the spell's actual level.</p>
</>};
const _zealous_mind = {title: "Zealous Mind", jsx: <><h2 id="feat-zealous_mind-zealous-mind">Zealous Mind</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 95</Link></p>
<p>You are so steadfast in the principles of your alignment, even magic has difficult swaying you.<br/><strong>Prerequisites:</strong> <Link to="/feat/iron_will">Iron Will</Link>, <Link to="/feat/unimpeachable_honor">Unimpeachable Honor</Link>, lawful alignment.<br/><strong>Benefit:</strong> Whenever you are under the effect of a charm or compulsion effect cast by or coming from a source with a chaotic alignment or an alignment on the good and evil axis opposite of your alignment (evil if you are good, and good if you are evil) you gain a +2 on any saving throw or opposed Charisma check to break free from the effect. This bonus stacks with itself and with the bonus granted by Unimpeachable Honor.</p>
</>};
